import{_ as a,c as e,o as m,b as s}from"./app.aaa68922.js";const u='{"title":"\u0421\u043F\u0430\u043D\u0434\u0430 \u043A\u0430\u0440\u0438\u043A\u0430","description":"","frontmatter":{"title":"\u0421\u043F\u0430\u043D\u0434\u0430 \u043A\u0430\u0440\u0438\u043A\u0430","subtitle":"\u0421\u0442\u0440\u043E\u0444\u044B \u043E \u0421\u043F\u0430\u043D\u0434\u0435","sans":"\u0938\u094D\u092A\u0928\u094D\u0926\u0915\u093E\u0930\u093F\u0915\u093E","trans":"Spandak\u0101rik\u0101","toc":true,"tags":"text","date":"2021-06-20T00:00:00.000Z"},"headers":[{"level":2,"title":"\u0427\u0430\u0441\u0442\u044C I: Svar\u016Bpaspanda","slug":"\u0447\u0430\u0441\u0442\u044C-i-svarupaspanda"},{"level":2,"title":"\u0427\u0430\u0441\u0442\u044C II: Sahajavidyodaya","slug":"\u0447\u0430\u0441\u0442\u044C-ii-sahajavidyodaya"},{"level":2,"title":"\u0427\u0430\u0441\u0442\u044C III: Vibh\u016Btispanda","slug":"\u0447\u0430\u0441\u0442\u044C-iii-vibhutispanda"},{"level":2,"title":"\u0427\u0430\u0441\u0442\u044C IV: \u042D\u043F\u0438\u043B\u043E\u0433","slug":"\u0447\u0430\u0441\u0442\u044C-iv-\u044D\u043F\u0438n\u043E\u0433"}],"relativePath":"texts/spanda-karika/index.md"}',t={},r=s('<p><a href="https://anavrita.com/ponyatie-spanda-problema-avtorstva-spanda-karik/" class="external-link" target="_blank" rel="noopener noreferrer">\u0411\u0445\u0430\u0442\u0442\u0430 \u041A\u0430\u043B\u043B\u0430\u0442\u0442\u0430, 9 \u0432\u0435\u043A \u043D.\u044D.</a></p><p><a href="http://sanskrit-sanscrito.com.ar/ru/spanda-karikas-normal-translation-trika-scriptures-non-dual-shaivism-of-kashmir-ru/564#spkI21to25" class="external-link" target="_blank" rel="noopener noreferrer">\u041F\u0435\u0440\u0435\u0432\u043E\u0434 \u043D\u0430 \u0430\u043D\u0433\u043B\u0438\u0439\u0441\u043A\u0438\u0439: \u0413\u0430\u0431\u0440\u0438\u044D\u043B\u044C \u041F\u0440\u0430\u0434\u0438\u0438\u043F\u0430\u043A\u0430, \u043F\u0435\u0440\u0435\u0432\u043E\u0434 \u043D\u0430 \u0440\u0443\u0441\u0441\u043A\u0438\u0439: \u0418\u0440\u0438\u043D\u0430 \u0412\u0430\u043B\u043B\u0430\u0431\u0445\u0430</a></p><h2 id="\u0447\u0430\u0441\u0442\u044C-i-svarupaspanda" tabindex="-1">\u0427\u0430\u0441\u0442\u044C I: Svar\u016Bpaspanda <a class="header-anchor" href="#\u0447\u0430\u0441\u0442\u044C-i-svarupaspanda" aria-hidden="true">#</a></h2><p>\u0421\u043F\u0430\u043D\u0434\u0430 \u043A\u0430\u043A \u0441\u0432\u043E\u044F \u0441\u043E\u0431\u0441\u0442\u0432\u0435\u043D\u043D\u0430\u044F \u043F\u0440\u0438\u0440\u043E\u0434\u0430</p><div class="stanza"><a href="#s1.1" id="s1.1" class="num">1.1</a><p class="sans">\u092F\u0938\u094D\u092F\u094B\u0928\u094D\u092E\u0947\u0937\u0928\u093F\u092E\u0947\u0937\u093E\u092D\u094D\u092F\u093E\u0902 \u091C\u0917\u0924\u0903 \u092A\u094D\u0930\u0932\u092F\u094B\u0926\u092F\u094C \u0964<br> \u0924\u0902 \u0936\u0915\u094D\u0924\u093F\u091A\u0915\u094D\u0930\u0935\u093F\u092D\u0935\u092A\u094D\u0930\u092D\u0935\u0902 \u0936\u0919\u094D\u0915\u0930\u0902 \u0938\u094D\u0924\u0941\u092E\u0903 \u0965\u0967\u0965</p><p class="trans">Yasyonme\u1E63anime\u1E63\u0101bhy\u0101\u1E41 jagata\u1E25 pralayodayau\u0964<br> Ta\u1E41 \u015Bakticakravibhavaprabhava\u1E41 \u015Ba\u1E45kara\u1E41 stuma\u1E25 \u09651\u0965</p><p>\u041C\u044B \u0432\u043E\u0441\u0445\u0432\u0430\u043B\u044F\u0435\u043C <em>(stuma\u1E25)</em> \u0442\u043E\u0433\u043E <em>(tam)</em> \u015Aa\u1E45kara --\u044D\u043F\u0438\u0442\u0435\u0442 \u0428\u0438\u0432\u044B-- <em>(\u015Ba\u1E45karam)</em>, \u043A\u043E\u0442\u043E\u0440\u044B\u0439 \u044F\u0432\u043B\u044F\u0435\u0442\u0441\u044F \u0438\u0441\u0442\u043E\u0447\u043D\u0438\u043A\u043E\u043C, \u0438\u043B\u0438 \u043F\u0440\u0438\u0447\u0438\u043D\u043E\u0439, <em>(prabhavam)</em> \u0432\u0435\u043B\u0438\u043A\u043E\u043B\u0435\u043F\u043D\u043E\u0439 <em>(vibhava)</em> \u0433\u0440\u0443\u043F\u043F\u044B <em>(cakra)</em> \u0441\u0438\u043B <em>(\u015Bakti)</em>, \u0447\u044C\u0438\u043C <em>(yasya)</em> \u043E\u0442\u043A\u0440\u044B\u0442\u0438\u0435\u043C [\u0438] \u0437\u0430\u043A\u0440\u044B\u0442\u0438\u0435\u043C \u0433\u043B\u0430\u0437 <em>(unme\u1E63a-nime\u1E63\u0101bhy\u0101m)</em> [\u0441\u043E\u0432\u0435\u0440\u0448\u0430\u0435\u0442\u0441\u044F] \u0440\u0430\u0441\u0442\u0432\u043E\u0440\u0435\u043D\u0438\u0435 \u0438 \u043F\u043E\u044F\u0432\u043B\u0435\u043D\u0438\u0435 <em>(pralaya-udayau)</em> \u043C\u0438\u0440\u0430 <em>(jagata\u1E25)</em>.</p></div><div class="stanza"><a href="#s1.2" id="s1.2" class="num">1.2</a><p class="sans">\u092F\u0924\u094D\u0930 \u0938\u094D\u0925\u093F\u0924\u092E\u093F\u0926\u0902 \u0938\u0930\u094D\u0935\u0902 \u0915\u093E\u0930\u094D\u092F\u0902 \u092F\u0938\u094D\u092E\u093E\u091A\u094D\u091A \u0928\u093F\u0930\u094D\u0917\u0924\u092E\u094D \u0964<br> \u0924\u0938\u094D\u092F\u093E\u0928\u093E\u0935\u0943\u0924\u0930\u0942\u092A\u0924\u094D\u0935\u093E\u0928\u094D\u0928 \u0928\u093F\u0930\u094B\u0927\u094B\u093D\u0938\u094D\u0924\u093F \u0915\u0941\u0924\u094D\u0930\u091A\u093F\u0924\u094D \u0965\u0968\u0965</p><p class="trans">Yatra sthitamida\u1E41 sarva\u1E41 k\u0101rya\u1E41 yasm\u0101cca nirgatam\u0964<br> Tasy\u0101n\u0101v\u1E5Btar\u016Bpatv\u0101nna nirodho&#39;sti kutracit \u09652\u0965</p><p>\u041F\u043E\u0441\u043A\u043E\u043B\u044C\u043A\u0443 \u041E\u043D \u043E\u0431\u043B\u0430\u0434\u0430\u0435\u0442 \u043D\u0435 \u0441\u043A\u0440\u044B\u0442\u043E\u0439 <em>(an\u0101v\u1E5Bta)</em> \u043F\u0440\u0438\u0440\u043E\u0434\u043E\u0439 --r\u016Bpa-- <em>(r\u016Bpatv\u0101t)</em>, \u043D\u0435\u0442 <em>(na.. asti)</em> \u0415\u043C\u0443 <em>(tasya)</em> \u043F\u0440\u0435\u0433\u0440\u0430\u0434 <em>(nirodha\u1E25)</em> \u043D\u0438\u0433\u0434\u0435 <em>(kutracid)</em>, [\u0442\u043E\u043C\u0443,] \u0432 \u043A\u043E\u043C <em>(yatra)</em> \u0432\u0441\u044F <em>(sarvam)</em> \u044D\u0442\u0430 <em>(idam)</em> \u0432\u0441\u0435\u043B\u0435\u043D\u043D\u0430\u044F <em>(k\u0101ryam)</em><sup>1</sup> \u043F\u043E\u043A\u043E\u0438\u0442\u0441\u044F <em>(sthitam)</em> \u0438 <em>(ca)</em> \u0438\u0437 \u043A\u043E\u0433\u043E <em>(yasm\u0101t)</em> \u043E\u043D\u0430 \u043F\u0440\u043E\u0438\u0437\u043E\u0448\u043B\u0430 <em>(nirgatam)</em>.</p><ol><li>\u0414\u043E\u0441\u043B. \xAB\u0441\u043B\u0435\u0434\u0441\u0442\u0432\u0438\u0435\xBB, \u0442\u043E \u0435\u0441\u0442\u044C \u0432\u0441\u0435\u043B\u0435\u043D\u043D\u0430\u044F \u044F\u0432\u043B\u044F\u0435\u0442\u0441\u044F \u0441\u043B\u0435\u0434\u0441\u0442\u0432\u0438\u0435\u043C, \u0430 \u0421\u043F\u0430\u043D\u0434\u0430 \u2014 \u043F\u0440\u0438\u0447\u0438\u043D\u043E\u0439.</li></ol></div><div class="stanza"><a href="#s1.3" id="s1.3" class="num">1.3</a><p class="sans">\u091C\u093E\u0917\u094D\u0930\u0926\u093E\u0926\u093F\u0935\u093F\u092D\u0947\u0926\u0947\u093D\u092A\u093F \u0924\u0926\u092D\u093F\u0928\u094D\u0928\u0947 \u092A\u094D\u0930\u0938\u0930\u094D\u092A\u0924\u093F \u0964<br> \u0928\u093F\u0935\u0930\u094D\u0924\u0924\u0947 \u0928\u093F\u091C\u093E\u0928\u094D\u0928\u0948\u0935 \u0938\u094D\u0935\u092D\u093E\u0935\u093E\u0926\u0941\u092A\u0932\u092C\u094D\u0927\u0943\u0924\u0903 \u0965\u0969\u0965</p><p class="trans">J\u0101grad\u0101divibhede&#39;pi tadabhinne prasarpati\u0964<br> Nivartate nij\u0101nnaiva svabh\u0101v\u0101dupalabdh\u1E5Bta\u1E25 \u09653\u0965</p><p>\u0414\u0430\u0436\u0435 <em>(api)</em> \u0432 \u0440\u0430\u0437\u043D\u043E\u043E\u0431\u0440\u0430\u0437\u0438\u0438 [\u0441\u043E\u0441\u0442\u043E\u044F\u043D\u0438\u0439 \u0441\u043E\u0437\u043D\u0430\u043D\u0438\u044F] <em>(vibhede)</em>, [\u0442\u0430\u043A\u0438\u0445 \u043A\u0430\u043A] \u0431\u043E\u0434\u0440\u0441\u0442\u0432\u043E\u0432\u0430\u043D\u0438\u0435 <em>(j\u0101grat)</em> \u0438 \u0442.\u0434. <em>(\u0101di)</em>, \u043A\u043E\u0442\u043E\u0440\u044B\u0435 \u043D\u0435\u043E\u0442\u0434\u0435\u043B\u0438\u043C\u044B <em>(abhinne)</em> \u043E\u0442 \u0442\u043E\u0433\u043E [\u0421\u043F\u0430\u043D\u0434\u044B] <em>(tad)</em>, [\u043F\u0440\u0438\u043D\u0446\u0438\u043F \u0421\u043F\u0430\u043D\u0434\u044B] \u043F\u0440\u043E\u0434\u043E\u043B\u0436\u0430\u0435\u0442 \u0442\u0435\u0447\u044C <em>(prasarpati)</em>. [\u0421\u043F\u0430\u043D\u0434\u0430 \u043D\u0438\u043A\u043E\u0433\u0434\u0430] \u043D\u0435 <em>(na eva)</em> \u043E\u0442\u0441\u0442\u0443\u043F\u0430\u0435\u0442 <em>(nivartate)</em> \u043E\u0442 \u0421\u0432\u043E\u0435\u0439 <em>(nij\u0101t)</em> \u0441\u0443\u0449\u043D\u043E\u0441\u0442\u043D\u043E\u0439 \u043F\u0440\u0438\u0440\u043E\u0434\u044B <em>(sva-bh\u0101v\u0101t)</em> \u0412\u043E\u0441\u043F\u0440\u0438\u043D\u0438\u043C\u0430\u044E\u0449\u0435\u0433\u043E <em>(upalabdh\u1E5Bta\u1E25)</em>.</p></div><div class="stanza"><a href="#s1.4" id="s1.4" class="num">1.4</a><p class="sans">\u0905\u0939\u0902 \u0938\u0941\u0916\u0940 \u091A \u0926\u0941\u0903\u0916\u0940 \u091A \u0930\u0915\u094D\u0924\u0936\u094D\u091A\u0947\u0924\u094D\u092F\u093E\u0926\u093F\u0938\u0902\u0935\u093F\u0926\u0903 \u0964<br> \u0938\u0941\u0916\u093E\u0926\u094D\u092F\u0935\u0938\u094D\u0925\u093E\u0928\u0941\u0938\u094D\u092F\u0942\u0924\u0947 \u0935\u0930\u094D\u0924\u0928\u094D\u0924\u0947\u093D\u0928\u094D\u092F\u0924\u094D\u0930 \u0924\u093E\u0903 \u0938\u094D\u092B\u0941\u091F\u092E\u094D \u0965\u096A\u0965</p><p class="trans">Aha\u1E41 sukh\u012B ca du\u1E25kh\u012B ca rakta\u015Bcety\u0101disa\u1E41vida\u1E25\u0964<br> Sukh\u0101dyavasth\u0101nusy\u016Bte vartante&#39;nyatra t\u0101\u1E25 sphu\u1E6Dam \u09654\u0965</p><p>\xAB\u042F <em>(aham)</em> \u0441\u0447\u0430\u0441\u0442\u043B\u0438\u0432 <em>(sukh\u012B ca)</em>\xBB, \xAB\u044F <em>(aham)</em> \u043E\u0433\u043E\u0440\u0447\u0451\u043D <em>(du\u1E25kh\u012B ca)</em>\xBB, \xAB\u044F <em>(aham)</em> \u043F\u0440\u0438\u0432\u044F\u0437\u0430\u043D <em>(rakta\u1E25 ca)</em>\xBB \u0438 \u0442.\u0434. <em>(iti-\u0101di)</em>. \u042D\u0442\u0438 <em>(t\u0101\u1E25)</em> \u043C\u044B\u0441\u043B\u0438*(sa\u1E41vida\u1E25)* \u044F\u0432\u043D\u043E <em>(sphu\u1E6Dam)</em> \u043E\u0441\u0442\u0430\u044E\u0442\u0441\u044F <em>(vartante)</em> \u0432 \u0434\u0440\u0443\u0433\u043E\u043C <em>(anyatra)</em>, [\u0432 \u0442\u043E\u043C,] \u0432 \u043A\u043E\u043C \u0441\u043E\u0441\u0442\u043E\u044F\u043D\u0438\u044F <em>(avasth\u0101)</em> \u0441\u0447\u0430\u0441\u0442\u044C\u044F <em>(sukha)</em> \u0438 \u0442.\u0434 <em>(\u0101di)</em> \u0441\u0432\u044F\u0437\u0430\u043D\u044B \u0432\u043C\u0435\u0441\u0442\u0435 [\u043F\u043E\u0434\u043E\u0431\u043D\u043E \u0431\u0443\u0441\u0438\u043D\u043A\u0430\u043C \u043E\u0436\u0435\u0440\u0435\u043B\u044C\u044F] <em>(anusy\u016Bte)</em>.</p></div><div class="stanza"><a href="#s1.5" id="s1.5" class="num">1.5</a><p class="sans">\u0928 \u0926\u0941\u0903\u0916\u0902 \u0928 \u0938\u0941\u0916\u0902 \u092F\u0924\u094D\u0930 \u0928 \u0917\u094D\u0930\u093E\u0939\u094D\u092F\u0902 \u0917\u094D\u0930\u093E\u0939\u0915\u0902 \u0928 \u091A \u0964<br> \u0928 \u091A\u093E\u0938\u094D\u0924\u093F \u092E\u0942\u0922\u092D\u093E\u0935\u094B\u093D\u092A\u093F \u0924\u0926\u0938\u094D\u0924\u093F \u092A\u0930\u092E\u093E\u0930\u094D\u0925\u0924\u0903 \u0965\u096B\u0965</p><p class="trans">Na du\u1E25kha\u1E41 na sukha\u1E41 yatra na gr\u0101hya\u1E41 gr\u0101haka\u1E41 na ca\u0964<br> Na c\u0101sti m\u016B\u1E0Dhabh\u0101vo&#39;pi tadasti param\u0101rthata\u1E25 \u09655\u0965</p><p>\u0422\u0430\u043C, \u0433\u0434\u0435 <em>(yatra)</em> [\u043D\u0435\u0442] \u043D\u0438 <em>(na)</em> \u0431\u043E\u043B\u0438 <em>(du\u1E25kham)</em>, \u043D\u0438 <em>(na)</em> \u043D\u0430\u0441\u043B\u0430\u0436\u0434\u0435\u043D\u0438\u044F <em>(sukham)</em>, \u043D\u0438 <em>(na)</em> \u043E\u0431\u044A\u0435\u043A\u0442\u0430 <em>(gr\u0101hyam)</em>, \u043D\u0438 <em>(na ca)</em> \u0441\u0443\u0431\u044A\u0435\u043A\u0442\u0430 <em>(gr\u0101hakam)</em>, \u0438 <em>(ca)</em> \u0434\u0430\u0436\u0435 <em>(api)</em> \u043D\u0435 <em>(na)</em> \u0441\u0443\u0449\u0435\u0441\u0442\u0432\u0443\u0435\u0442 <em>(asti)</em> \u0441\u043E\u0441\u0442\u043E\u044F\u043D\u0438\u044F <em>(bh\u0101va\u1E25)</em> \u0431\u0435\u0441\u0441\u043E\u0437\u043D\u0430\u0442\u0435\u043B\u044C\u043D\u043E\u0441\u0442\u0438 <em>(m\u016B\u1E0Dha)</em> , \u0442\u043E <em>(tad)</em>, \u0432 \u0432\u044B\u0441\u0448\u0435\u043C \u0441\u043C\u044B\u0441\u043B\u0435 <em>(param\u0101rthatas)</em>, \u0435\u0441\u0442\u044C <em>(asti)</em> [\u043F\u0440\u0438\u043D\u0446\u0438\u043F \u0421\u043F\u0430\u043D\u0434\u044B].</p></div><div class="stanza"><a href="#s1.6-1.7" id="s1.6-1.7" class="num">1.6-1.7</a><p class="sans">\u092F\u0924\u0903 \u0915\u0930\u0923\u0935\u0930\u094D\u0917\u094B\u093D\u092F\u0902 \u0935\u093F\u092E\u0942\u0922\u094B\u093D\u092E\u0942\u0922\u0935\u0924\u094D\u0938\u094D\u0935\u092F\u092E\u094D \u0964<br> \u0938\u0939\u093E\u0928\u094D\u0924\u0930\u0947\u0923 \u091A\u0915\u094D\u0930\u0947\u0923 \u092A\u094D\u0930\u0935\u0943\u0924\u094D\u0924\u093F\u0938\u094D\u0925\u093F\u0924\u093F\u0938\u0902\u0939\u0943\u0924\u0940\u0903 \u0965\u096C \u0965</p><p class="sans">\u0932\u092D\u0924\u0947 \u0924\u0924\u094D\u092A\u094D\u0930\u092F\u0924\u094D\u0928\u0947\u0928 \u092A\u0930\u0940\u0915\u094D\u0937\u094D\u092F\u0902 \u0924\u0924\u094D\u0924\u094D\u0935\u092E\u093E\u0926\u0930\u093E\u0924\u094D \u0964<br> \u092F\u0924\u0903 \u0938\u094D\u0935\u0924\u0928\u094D\u0924\u094D\u0930\u0924\u093E \u0924\u0938\u094D\u092F \u0938\u0930\u094D\u0935\u0924\u094D\u0930\u0947\u092F\u092E\u0915\u0943\u0924\u094D\u0930\u093F\u092E\u093E \u0965\u096D \u0965</p><p class="trans">Yata\u1E25 kara\u1E47avargo&#39;ya\u1E41 vim\u016B\u1E0Dho&#39;m\u016B\u1E0Dhavatsvayam\u0964<br> Sah\u0101ntare\u1E47a cakre\u1E47a prav\u1E5Bttisthitisa\u1E41h\u1E5Bt\u012B\u1E25 \u09656\u0965</p><p class="trans">Labhate tatprayatnena par\u012Bk\u1E63ya\u1E41 tattvam\u0101dar\u0101t\u0964<br> Yata\u1E25 svatantrat\u0101 tasya sarvatreyamak\u1E5Btrim\u0101 \u09657\u0965</p><p>\u0422\u043E\u0442 <em>(tad)</em> \u043F\u0440\u0438\u043D\u0446\u0438\u043F [\u0421\u043F\u0430\u043D\u0434\u044B] <em>(tattvam)</em> \u0434\u043E\u043B\u0436\u0435\u043D \u0431\u044B\u0442\u044C \u0432\u043D\u0438\u043C\u0430\u0442\u0435\u043B\u044C\u043D\u043E \u0438\u0437\u0443\u0447\u0435\u043D <em>(par\u012Bk\u1E63yam... prayatnena)</em> [\u0438] \u0443\u0432\u0430\u0436\u0430\u0435\u043C <em>(\u0101dar\u0101t)</em>, \u0441 \u043F\u043E\u043C\u043E\u0449\u044C\u044E \u043A\u043E\u0442\u043E\u0440\u043E\u0433\u043E <em>(yatas)</em> \u044D\u0442\u0430 <em>(ayam)</em> \u0433\u0440\u0443\u043F\u043F\u0430 <em>(varga\u1E25)</em> \u043E\u0440\u0433\u0430\u043D\u043E\u0432 --\u0438\u043D\u0442\u0435\u043B\u043B\u0435\u043A\u0442, \u044D\u0433\u043E, \u0443\u043C, \u0441\u0438\u043B\u044B \u0432\u043E\u0441\u043F\u0440\u0438\u044F\u0442\u0438\u044F \u0438 \u0434\u0435\u0439\u0441\u0442\u0432\u0438\u044F-- <em>(kara\u1E47a)</em>^ 1^ [\u0431\u0443\u0434\u0443\u0447\u0438] \u043D\u0435\u043E\u0434\u0443\u0448\u0435\u0432\u043B\u0451\u043D\u043D\u043E\u0439 <em>(vim\u016B\u1E0Dha\u1E25)</em>, [\u0432\u0435\u0434\u0451\u0442 \u0441\u0435\u0431\u044F] \u043A\u0430\u043A <em>(vat)</em> \u0441\u0430\u043C\u043E\u0441\u0442\u043E\u044F\u0442\u0435\u043B\u044C\u043D\u043E <em>(svayam)</em> \u043E\u0434\u0443\u0448\u0435\u0432\u043B\u0451\u043D\u043D\u0430\u044F <em>(am\u016B\u1E0Dha)</em>, [\u0438] \u0432\u043C\u0435\u0441\u0442\u0435 <em>(saha)</em> \u0441 \u0432\u043D\u0443\u0442\u0440\u0435\u043D\u043D\u0435\u0439 <em>(\u0101ntare\u1E47a)</em> \u0433\u0440\u0443\u043F\u043F\u043E\u0439 [\u0438\u0437 Kara\u1E47e\u015Bvar\u012B, \u0431\u043E\u0433\u0438\u043D\u044C \u0447\u0443\u0432\u0441\u0442\u0432] <em>(cakre\u1E47a)</em> \u0432\u0445\u043E\u0434\u0438\u0442 <em>(labhate)</em> \u0432 \u0441\u043E\u0441\u0442\u043E\u044F\u043D\u0438\u044F prav\u1E5Btti --\u0443\u0441\u0442\u0440\u0435\u043C\u043B\u0435\u043D\u0438\u044F \u043A \u0432\u043D\u0435\u0448\u043D\u0438\u043C \u043E\u0431\u044A\u0435\u043A\u0442\u0430\u043C-- <em>(prav\u1E5Btti)</em>, sthiti --\u043F\u043E\u0434\u0434\u0435\u0440\u0436\u0430\u043D\u0438\u044F \u044D\u0442\u0438\u0445 \u0432\u043D\u0435\u0448\u043D\u0438\u0445 \u043E\u0431\u044A\u0435\u043A\u0442\u043E\u0432 \u043A\u0430\u043A\u043E\u0435-\u0442\u043E \u0432\u0440\u0435\u043C\u044F-- <em>(sthiti)</em> [\u0438] sa\u1E41h\u1E5Bti --\u0440\u0430\u0441\u0442\u0432\u043E\u0440\u0435\u043D\u0438\u044F \u044D\u0442\u0438\u0445 \u043E\u0431\u044A\u0435\u043A\u0442\u043E\u0432 \u0432 \u0441\u0432\u043E\u0451\u043C \u0412\u044B\u0441\u0448\u0435\u043C \u042F-- <em>(sa\u1E41h\u1E5Bt\u012B\u1E25)</em>, \u043F\u043E\u0441\u043A\u043E\u043B\u044C\u043A\u0443 <em>(yatas)</em> \u0442\u0430\u043A\u0430\u044F <em>(iyam)</em> \u0415\u0433\u043E <em>(tasya)</em> \u0435\u0441\u0442\u0435\u0441\u0442\u0432\u0435\u043D\u043D\u0430\u044F <em>(ak\u1E5Btrim\u0101)</em> \u0421\u0432\u043E\u0431\u043E\u0434\u0430 <em>(svatantrat\u0101)</em> [\u0441\u0443\u0449\u0435\u0441\u0442\u0432\u0443\u0435\u0442] \u043F\u043E\u0432\u0441\u0435\u043C\u0435\u0441\u0442\u043D\u043E <em>(sarvatra)</em>.</p><ol><li>\u0422\u043E \u0435\u0441\u0442\u044C \u043F\u044F\u0442\u044C j\xF1\u0101nendriya <em>(\u0441\u0438\u043B \u0432\u043E\u0441\u043F\u0440\u0438\u044F\u0442\u0438\u044F)</em>, \u043F\u044F\u0442\u044C karmendriya <em>(\u0441\u0438\u043B \u0434\u0435\u0439\u0441\u0442\u0432\u0438\u044F)</em>, \u0443\u043C, \u044D\u0433\u043E \u0438 \u0438\u043D\u0442\u0435\u043B\u043B\u0435\u043A\u0442.</li></ol></div><div class="stanza"><a href="#s1.8" id="s1.8" class="num">1.8</a><p class="sans">\u0928 \u0939\u0940\u091A\u094D\u091B\u093E\u0928\u094B\u0926\u0928\u0938\u094D\u092F\u093E\u092F\u0902 \u092A\u094D\u0930\u0947\u0930\u0915\u0924\u094D\u0935\u0947\u0928 \u0935\u0930\u094D\u0924\u0924\u0947 \u0964<br> \u0905\u092A\u093F \u0924\u094D\u0935\u093E\u0924\u094D\u092E\u092C\u0932\u0938\u094D\u092A\u0930\u094D\u0936\u093E\u0924\u094D\u092A\u0941\u0930\u0941\u0937\u0938\u094D\u0924\u0924\u094D\u0938\u092E\u094B \u092D\u0935\u0947\u0924\u094D \u0965\u096E\u0965</p><p class="trans">Na h\u012Bcch\u0101nodanasy\u0101ya\u1E41 prerakatvena vartate\u0964<br> Api tv\u0101tmabalaspar\u015B\u0101tpuru\u1E63astatsamo bhavet \u09658\u0965</p><p>\u042D\u0442\u0430 [\u043E\u0433\u0440\u0430\u043D\u0438\u0447\u0435\u043D\u043D\u0430\u044F \u043B\u0438\u0447\u043D\u043E\u0441\u0442\u044C] <em>(ayam)</em> \u043D\u0435 <em>(na hi)</em> \u0443\u043F\u0440\u0430\u0432\u043B\u044F\u0435\u0442 <em>(prerakatvena vartate)</em> \u0438\u043C\u043F\u0443\u043B\u044C\u0441\u043E\u043C <em>(nodanasya)</em> \u0436\u0435\u043B\u0430\u043D\u0438\u044F <em>(icch\u0101)</em>, \u043D\u043E \u0432\u0441\u0451 \u0436\u0435 <em>(api tu)</em>, \u0432\u043E\u0439\u0434\u044F \u0432 \u043A\u043E\u043D\u0442\u0430\u043A\u0442 <em>(spar\u015B\u0101t)</em> \u0441 \u0421\u0438\u043B\u043E\u0439 <em>(bala)</em> \u0412\u044B\u0441\u0448\u0435\u0433\u043E \u042F <em>(\u0101tma)</em>, \u0438\u043D\u0434\u0438\u0432\u0438\u0434 <em>(puru\u1E63a\u1E25)</em> \u0441\u0442\u0430\u043D\u043E\u0432\u0438\u0442\u0441\u044F <em>(bhavet)</em> \u0440\u0430\u0432\u043D\u044B\u043C <em>(sama\u1E25)</em> \u0422\u043E\u043C\u0443 <em>(tad)</em>.</p></div><div class="stanza"><a href="#s1.9" id="s1.9" class="num">1.9</a><p class="sans">\u0928\u093F\u091C\u093E\u0936\u0941\u0926\u094D\u0927\u094D\u092F\u093E\u0938\u092E\u0930\u094D\u0925\u0938\u094D\u092F \u0915\u0930\u094D\u0924\u0935\u094D\u092F\u0947\u0937\u094D\u0935\u092D\u093F\u0932\u093E\u0937\u093F\u0923\u0903 \u0964<br> \u092F\u0926\u093E \u0915\u094D\u0937\u094B\u092D\u0903 \u092A\u094D\u0930\u0932\u0940\u092F\u0947\u0924 \u0924\u0926\u093E \u0938\u094D\u092F\u093E\u0924\u094D\u092A\u0930\u092E\u0902 \u092A\u0926\u092E\u094D \u0965\u096F\u0965</p><p class="trans">Nij\u0101\u015Buddhy\u0101samarthasya kartavye\u1E63vabhil\u0101\u1E63i\u1E47a\u1E25\u0964<br> Yad\u0101 k\u1E63obha\u1E25 pral\u012Byeta tad\u0101 sy\u0101tparama\u1E41 padam \u09659\u0965</p><p>\u041A\u043E\u0433\u0434\u0430 <em>(yad\u0101)</em> \u0432\u043E\u0437\u0431\u0443\u0436\u0434\u0435\u043D\u0438\u0435 <em>(k\u1E63obha\u1E25)</em> \u0442\u043E\u0433\u043E [\u043E\u0433\u0440\u0430\u043D\u0438\u0447\u0435\u043D\u043D\u043E\u0433\u043E \u0441\u0443\u0449\u0435\u0441\u0442\u0432\u0430], \u043D\u0435\u043C\u043E\u0449\u043D\u043E\u0433\u043E <em>(asamarthasya)</em> \u0438\u0437-\u0437\u0430 \u0435\u0433\u043E \u0441\u043E\u0431\u0441\u0442\u0432\u0435\u043D\u043D\u043E\u0439 <em>(nija)</em> \u043D\u0435\u0447\u0438\u0441\u0442\u043E\u0442\u044B --a\u015Buddhi-- <em>(a\u015Buddhy\u0101)</em>, [\u0438] \u0436\u0435\u043B\u0430\u044E\u0449\u0435\u0433\u043E --abhil\u0101\u1E63\u012B-- <em>(abhil\u0101\u1E63i\u1E47a\u1E25)</em> \u0434\u0435\u0439\u0441\u0442\u0432\u043E\u0432\u0430\u0442\u044C <em>(kartavye\u1E63u)</em>, \u043F\u043E\u043B\u043D\u043E\u0441\u0442\u044C\u044E \u0440\u0430\u0441\u0442\u0432\u043E\u0440\u044F\u0435\u0442\u0441\u044F <em>(pral\u012Byeta)</em>, \u0442\u043E\u0433\u0434\u0430 <em>(tad\u0101)</em> \u043D\u0430\u0441\u0442\u0443\u043F\u0430\u0435\u0442 <em>(sy\u0101t)</em> \u0412\u044B\u0441\u0448\u0435\u0435 <em>(paramam)</em> \u0421\u043E\u0441\u0442\u043E\u044F\u043D\u0438\u0435 <em>(padam)</em>.</p></div><div class="stanza"><a href="#s1.10" id="s1.10" class="num">1.10</a><p class="sans">\u0924\u0926\u093E\u0938\u094D\u092F\u093E\u0915\u0943\u0924\u094D\u0930\u093F\u092E\u094B \u0927\u0930\u094D\u092E\u094B \u091C\u094D\u091E\u0924\u094D\u0935\u0915\u0930\u094D\u0924\u0943\u0924\u094D\u0935\u0932\u0915\u094D\u0937\u0923\u0903 \u0964<br> \u092F\u0924\u0938\u094D\u0924\u0926\u0947\u092A\u094D\u0938\u093F\u0924\u0902 \u0938\u0930\u094D\u0935\u0902 \u091C\u093E\u0928\u093E\u0924\u093F \u091A \u0915\u0930\u094B\u0924\u093F \u091A \u0965\u0967\u0966\u0965</p><p class="trans">Tad\u0101sy\u0101k\u1E5Btrimo dharmo j\xF1atvakart\u1E5Btvalak\u1E63a\u1E47a\u1E25\u0964<br> Yatastadepsita\u1E41 sarva\u1E41 j\u0101n\u0101ti ca karoti ca \u096510\u0965</p><p>\u0417\u0430\u0442\u0435\u043C <em>(tad\u0101)</em> [\u043F\u043E\u044F\u0432\u043B\u044F\u0435\u0442\u0441\u044F] \u0435\u0433\u043E <em>(asya)</em> \u0432\u0440\u043E\u0436\u0434\u0451\u043D\u043D\u0430\u044F <em>(ak\u1E5Btrima\u1E25)</em> \u043F\u0440\u0438\u0440\u043E\u0434\u0430 <em>(dharma\u1E25)</em>, \u0445\u0430\u0440\u0430\u043A\u0442\u0435\u0440\u0438\u0437\u0443\u0435\u043C\u0430\u044F <em>(lak\u1E63a\u1E47a\u1E25)</em> \u0437\u043D\u0430\u043D\u0438\u0435\u043C <em>(j\xF1atva)</em> [\u0438] \u0434\u0435\u0439\u0441\u0442\u0432\u0438\u0435\u043C <em>(kart\u1E5Btva)</em>, \u0437\u0430 \u0441\u0447\u0451\u0442 \u043A\u043E\u0442\u043E\u0440\u043E\u0439 <em>(yatas)</em> [\u0442\u043E\u0442 \u0447\u0435\u043B\u043E\u0432\u0435\u043A] \u0442\u043E\u0433\u0434\u0430 <em>(tad\u0101)</em> \u0437\u043D\u0430\u0435\u0442 <em>(j\u0101n\u0101ti)</em> \u0438 <em>(ca... ca)</em> \u0434\u0435\u043B\u0430\u0435\u0442 <em>(karoti)</em> \u0432\u0441\u0451 <em>(sarvam)</em> \u0436\u0435\u043B\u0430\u0435\u043C\u043E\u0435 <em>(\u012Bpsitam)</em>.</p></div><div class="stanza"><a href="#s1.11" id="s1.11" class="num">1.11</a><p class="sans">\u0924\u092E\u0927\u093F\u0937\u094D\u0920\u093E\u0924\u0943\u092D\u093E\u0935\u0947\u0928 \u0938\u094D\u0935\u092D\u093E\u0935\u092E\u0935\u0932\u094B\u0915\u092F\u0928\u094D \u0964<br> \u0938\u094D\u092E\u092F\u092E\u093E\u0928 \u0907\u0935\u093E\u0938\u094D\u0924\u0947 \u092F\u0938\u094D\u0924\u0938\u094D\u092F\u0947\u092F\u0902 \u0915\u0941\u0938\u0943\u0924\u093F\u0903 \u0915\u0941\u0924\u0903 \u0965\u0967\u0967 \u0965</p><p class="trans">Tamadhi\u1E63\u1E6Dh\u0101t\u1E5Bbh\u0101vena svabh\u0101vamavalokayan\u0964<br> Smayam\u0101na iv\u0101ste yastasyeya\u1E41 kus\u1E5Bti\u1E25 kuta\u1E25 \u096511\u0965</p><p>\u041A\u0430\u043A <em>(kutas)</em> [\u043C\u043E\u0436\u0435\u0442] \u044D\u0442\u043E\u0442 <em>(iyam)</em> \u043E\u0442\u0432\u0440\u0430\u0442\u0438\u0442\u0435\u043B\u044C\u043D\u044B\u0439 <em>(ku)</em> \u043F\u0443\u0442\u044C \u0442\u0440\u0430\u043D\u0441\u043C\u0438\u0433\u0440\u0430\u0446\u0438\u0438 <em>(s\u1E5Bti\u1E25)</em> [\u043F\u0440\u0438\u043D\u0430\u0434\u043B\u0435\u0436\u0430\u0442\u044C] \u0442\u043E\u043C\u0443 <em>(tasya)</em>, \u043A\u0442\u043E <em>(ya\u1E25)</em> \u043A\u0430\u043A \u0431\u044B <em>(iva)</em> \u043F\u0440\u0435\u0431\u044B\u0432\u0430\u0435\u0442 <em>(\u0101ste)</em> \u0432 \u0438\u0437\u0443\u043C\u043B\u0435\u043D\u0438\u0438 <em>(smayam\u0101na\u1E25)</em>, \u0441\u043E\u0437\u0435\u0440\u0446\u0430\u044F <em>(avalokayan)</em> \u0442\u0443 <em>(tam)</em> \u0438\u0441\u0442\u0438\u043D\u043D\u0443\u044E \u043F\u0440\u0438\u0440\u043E\u0434\u0443 [\u0421\u043F\u0430\u043D\u0434\u0443] <em>(sva-bh\u0101vam)</em> \u043A\u0430\u043A <em>(bh\u0101vena)</em> \u0433\u043E\u0441\u043F\u043E\u0434\u0441\u0442\u0432\u0443\u044E\u0449\u0443\u044E [\u043D\u0430\u0434 \u0432\u0441\u0435\u0439 \u0432\u0441\u0435\u043B\u0435\u043D\u043D\u043E\u0439] <em>(adhi\u1E63\u1E6Dh\u0101t\u1E5B)</em>?</p></div><div class="stanza"><a href="#s1.12" id="s1.12" class="num">1.12</a><p class="sans">\u0928\u093E\u092D\u093E\u0935\u094B \u092D\u093E\u0935\u094D\u092F\u0924\u093E\u092E\u0947\u0924\u093F \u0928 \u091A \u0924\u0924\u094D\u0930\u093E\u0938\u094D\u0924\u094D\u092F\u092E\u0942\u0922\u0924\u093E \u0964<br> \u092F\u0924\u094B\u093D\u092D\u093F\u092F\u094B\u0917\u0938\u0902\u0938\u094D\u092A\u0930\u094D\u0936\u093E\u0924\u094D\u0924\u0926\u093E\u0938\u0940\u0926\u093F\u0924\u093F \u0928\u093F\u0936\u094D\u091A\u092F\u0903 \u0965\u0967\u0968\u0965</p><p class="trans">N\u0101bh\u0101vo bh\u0101vyat\u0101meti na ca tatr\u0101styam\u016B\u1E0Dhat\u0101\u0964<br> Yato&#39;bhiyogasa\u1E41spar\u015B\u0101ttad\u0101s\u012Bditi ni\u015Bcaya\u1E25 \u096512\u0965</p><p>\u041D\u0435\u0431\u044B\u0442\u0438\u0435 <em>(abh\u0101va\u1E25)</em> \u043D\u0435\u0432\u043E\u0437\u043C\u043E\u0436\u043D\u043E <em>(na)</em> \u0441\u043E\u0437\u0435\u0440\u0446\u0430\u0442\u044C <em>(bh\u0101vyat\u0101m eti)</em>, \u0430 \u0442\u0430\u043A\u0436\u0435 <em>(ca)</em> \u043D\u0435 \u0441\u0443\u0449\u0435\u0441\u0442\u0432\u0443\u0435\u0442 <em>(na... asti)</em> \u043E\u0442\u0441\u0443\u0442\u0441\u0442\u0432\u0438\u044F \u043E\u0446\u0435\u043F\u0435\u043D\u0435\u043D\u0438\u044F <em>(am\u016B\u1E0Dhat\u0101)</em> \u0432 \u044D\u0442\u043E\u043C [\u0441\u043E\u0441\u0442\u043E\u044F\u043D\u0438\u0438] <em>(tatra)</em>, \u043F\u043E\u0442\u043E\u043C\u0443 \u0447\u0442\u043E <em>(yatas)</em> \u043F\u0440\u0438 \u043A\u043E\u043D\u0442\u0430\u043A\u0442\u0435 <em>(sa\u1E41spar\u015B\u0101t)</em> \u0441 abhiyoga --\u0443\u0441\u043B\u044B\u0448\u0430\u0432 \u043F\u043E\u043A\u0430\u0437\u0430\u043D\u0438\u0435 \u0447\u0435\u043B\u043E\u0432\u0435\u043A\u0430, \u0442\u043E\u043B\u044C\u043A\u043E \u0447\u0442\u043E \u0432\u0435\u0440\u043D\u0443\u0432\u0448\u0435\u0433\u043E\u0441\u044F \u0438\u0437 \u044D\u0442\u043E\u0433\u043E \u0441\u043E\u0441\u0442\u043E\u044F\u043D\u0438\u044F -- <em>(abhiyoga\u1E25)</em><sup>1</sup>, \u043F\u043E\u0434\u0442\u0432\u0435\u0440\u0436\u0434\u0430\u0435\u0442\u0441\u044F <em>(iti ni\u015Bcaya\u1E25)</em>, \u0447\u0442\u043E \u0442\u043E --\u043E\u0446\u0435\u043F\u0435\u043D\u0435\u043D\u0438\u0435-- <em>(tad)</em> [\u0434\u0435\u0439\u0441\u0442\u0432\u0438\u0442\u0435\u043B\u044C\u043D\u043E] \u0438\u043C\u0435\u043B\u043E \u043C\u0435\u0441\u0442\u043E \u0431\u044B\u0442\u044C <em>(\u0101s\u012Bt)</em>.</p><ol><li>\u041D\u0435\u0441\u043C\u043E\u0442\u0440\u044F \u043D\u0430 \u0442\u043E, \u0447\u0442\u043E abhiyoga \u0434\u043E\u0441\u043B\u043E\u0432\u043D\u043E \u043E\u0437\u043D\u0430\u0447\u0430\u0435\u0442 \xAB\u043F\u0440\u0438\u043C\u0435\u043D\u0435\u043D\u0438\u0435\xBB, \u0432 \u044D\u0442\u043E\u043C \u043A\u043E\u043D\u0442\u0435\u043A\u0441\u0442\u0435 \u0438\u043C\u0435\u0435\u0442\u0441\u044F \u0432 \u0432\u0438\u0434\u0443 \xAB\u043F\u043E\u043A\u0430\u0437\u0430\u043D\u0438\u0435 \u0447\u0435\u043B\u043E\u0432\u0435\u043A\u0430, \u0442\u043E\u043B\u044C\u043A\u043E \u0447\u0442\u043E \u0432\u0435\u0440\u043D\u0443\u0432\u0448\u0435\u0433\u043E\u0441\u044F \u0438\u0437 sam\u0101dhi, \u0441\u043E\u0432\u0435\u0440\u0448\u0435\u043D\u043D\u043E\u0439 \u043A\u043E\u043D\u0446\u0435\u043D\u0442\u0440\u0430\u0446\u0438\u0438\xBB. \u0422\u0430\u043A\u043E\u0435 \u0442\u043E\u043B\u043A\u043E\u0432\u0430\u043D\u0438\u0435 \u043D\u0435 \u043F\u0440\u0438\u0434\u0443\u043C\u0430\u043D\u043E \u043C\u043D\u043E\u044E, \u0430 \u0432\u0437\u044F\u0442\u043E \u0438\u0437 Spandanir\u1E47aya, \u043D\u0430\u0438\u0431\u043E\u043B\u0435\u0435 \u0430\u0432\u0442\u043E\u0440\u0438\u0442\u0435\u0442\u043D\u043E\u0433\u043E \u043A\u043E\u043C\u043C\u0435\u043D\u0442\u0430\u0440\u0438\u044F \u043A Spandak\u0101rik\u0101-s \u043C\u0443\u0434\u0440\u0435\u0446\u0430 K\u1E63emar\u0101ja.</li></ol></div><div class="stanza"><a href="#s1.13" id="s1.13" class="num">1.13</a><p class="sans">\u0905\u0924\u0938\u094D\u0924\u0924\u094D\u0915\u0943\u0924\u094D\u0930\u093F\u092E\u0902 \u091C\u094D\u091E\u0947\u092F\u0902 \u0938\u094C\u0937\u0941\u092A\u094D\u0924\u092A\u0926\u0935\u0924\u094D\u0938\u0926\u093E \u0964<br> \u0928 \u0924\u094D\u0935\u0947\u0935\u0902 \u0938\u094D\u092E\u0930\u094D\u092F\u092E\u093E\u0923\u0924\u094D\u0935\u0902 \u0924\u0924\u094D\u0924\u0924\u094D\u0924\u094D\u0935\u0902 \u092A\u094D\u0930\u0924\u093F\u092A\u0926\u094D\u092F\u0924\u0947 \u0965\u0967\u0969\u0965</p><p class="trans">Atastatk\u1E5Btrima\u1E41 j\xF1eya\u1E41 sau\u1E63uptapadavatsad\u0101\u0964<br> Na tveva\u1E41 smaryam\u0101\u1E47atva\u1E41 tattattva\u1E41 pratipadyate \u096513\u0965</p><p>\u041F\u043E \u044D\u0442\u043E\u0439 \u043F\u0440\u0438\u0447\u0438\u043D\u0435 <em>(atas)</em>, \u0442\u043E <em>(tad)</em> \u0438\u0441\u043A\u0443\u0441\u0441\u0442\u0432\u0435\u043D\u043D\u043E\u0435 <em>(k\u1E5Btrimam)</em> \u043F\u043E\u0437\u043D\u0430\u0432\u0430\u0435\u043C\u043E\u0435 <em>(j\xF1eyam)</em><sup>1</sup> \u0432\u0441\u0435\u0433\u0434\u0430 <em>(sad\u0101)</em> \u043F\u043E\u0434\u043E\u0431\u043D\u043E <em>(vat)</em> \u0441\u043E\u0441\u0442\u043E\u044F\u043D\u0438\u044E <em>(pada)</em> \u0433\u043B\u0443\u0431\u043E\u043A\u043E\u0433\u043E \u0441\u043D\u0430 <em>(sau\u1E63upta)</em>. \u0422\u0435\u043C \u043D\u0435 \u043C\u0435\u043D\u0435\u0435 <em>(tu)</em>, \u0442\u043E\u0442 <em>(tad)</em> \u043F\u0440\u0438\u043D\u0446\u0438\u043F [\u0421\u043F\u0430\u043D\u0434\u044B] <em>(tattvam)</em> \u0432\u043E\u0441\u043F\u0440\u0438\u043D\u0438\u043C\u0430\u0435\u0442\u0441\u044F \u0438\u043B\u0438 \u043E\u0441\u043E\u0437\u043D\u0430\u0451\u0442\u0441\u044F <em>(pratipadyate)</em> \u043D\u0435 <em>(na)</em> \u0442\u0430\u043A <em>(evam)</em> \u043A\u0430\u043A \u0432\u043E\u0441\u043F\u043E\u043C\u0438\u043D\u0430\u043D\u0438\u0435 <em>(smaryam\u0101\u1E47atvam)</em>.</p><ol><li>\u0417\u0434\u0435\u0441\u044C \u0433\u043E\u0432\u043E\u0440\u0438\u0442\u0441\u044F \u043E \u043D\u0435\u0431\u044B\u0442\u0438\u0438, \u0443\u043F\u043E\u043C\u044F\u043D\u0443\u0442\u043E\u043C \u0432 \u043F\u0440\u0435\u0434\u044B\u0434\u0443\u0449\u0435\u0439 \u0441\u0442\u0440\u043E\u0444\u0435.</li></ol></div><div class="stanza"><a href="#s1.14" id="s1.14" class="num">1.14</a><p class="sans">\u0905\u0935\u0938\u094D\u0925\u093E\u092F\u0941\u0917\u0932\u0902 \u091A\u093E\u0924\u094D\u0930 \u0915\u093E\u0930\u094D\u092F\u0915\u0930\u094D\u0924\u0943\u0924\u094D\u0935\u0936\u092C\u094D\u0926\u093F\u0924\u092E\u094D \u0964<br> \u0915\u093E\u0930\u094D\u092F\u0924\u093E \u0915\u094D\u0937\u092F\u093F\u0923\u0940 \u0924\u0924\u094D\u0930 \u0915\u0930\u094D\u0924\u0943\u0924\u094D\u0935\u0902 \u092A\u0941\u0928\u0930\u0915\u094D\u0937\u092F\u092E\u094D \u0965\u0967\u096A\u0965</p><p class="trans">Avasth\u0101yugala\u1E41 c\u0101tra k\u0101ryakart\u1E5Btva\u015Babditam\u0964<br> K\u0101ryat\u0101 k\u1E63ayi\u1E47\u012B tatra kart\u1E5Btva\u1E41 punarak\u1E63ayam \u096514\u0965</p><p>\u0413\u043E\u0432\u043E\u0440\u0438\u0442\u0441\u044F <em>(\u015Babditam)</em>, \u0447\u0442\u043E [\u0441\u0443\u0449\u0435\u0441\u0442\u0432\u0443\u044E\u0442] \u0434\u0432\u0430 <em>(yugalam)</em> \u0441\u043E\u0441\u0442\u043E\u044F\u043D\u0438\u044F <em>(avasth\u0101)</em> \u0432 \u044D\u0442\u043E\u043C [\u043F\u0440\u0438\u043D\u0446\u0438\u043F\u0435 \u0421\u043F\u0430\u043D\u0434\u044B] <em>(ca atra)</em>: \u0441\u043E\u0441\u0442\u043E\u044F\u043D\u0438\u0435 \u0434\u0435\u043B\u0430\u043D\u0438\u044F <em>(k\u0101rya... tva)</em> [\u0438] \u0441\u043E\u0441\u0442\u043E\u044F\u043D\u0438\u0435 \u0434\u0435\u043B\u0430\u0442\u0435\u043B\u044F <em>(kart\u1E5Btva)</em>. \u0415\u0441\u0442\u0435\u0441\u0442\u0432\u0435\u043D\u043D\u043E <em>(tatra)</em>, \u0441\u043E\u0441\u0442\u043E\u044F\u043D\u0438\u0435 \u0434\u0435\u043B\u0430\u043D\u0438\u044F <em>(k\u0101ryat\u0101)</em> \u0431\u0440\u0435\u043D\u043D\u043E <em>(k\u1E63ayi\u1E47\u012B)</em>, \u0430 <em>(punar)</em> \u0441\u043E\u0441\u0442\u043E\u044F\u043D\u0438\u0435 \u0434\u0435\u043B\u0430\u0442\u0435\u043B\u044F <em>(kart\u1E5Btvam)</em> \u043D\u0435\u0442\u043B\u0435\u043D\u043D\u043E <em>(ak\u1E63ayam)</em>.</p></div><div class="stanza"><a href="#s1.15" id="s1.15" class="num">1.15</a><p class="sans">\u0915\u093E\u0930\u094D\u092F\u094B\u0928\u094D\u092E\u0941\u0916\u0903 \u092A\u094D\u0930\u092F\u0924\u094D\u0928\u094B \u092F\u0903 \u0915\u0947\u0935\u0932\u0902 \u0938\u094B\u093D\u0924\u094D\u0930 \u0932\u0941\u092A\u094D\u092F\u0924\u0947 \u0964<br> \u0924\u0938\u094D\u092E\u093F\u0901\u0932\u094D\u0932\u0941\u092A\u094D\u0924\u0947 \u0935\u093F\u0932\u0941\u092A\u094D\u0924\u094B\u093D\u0938\u094D\u092E\u0940\u0924\u094D\u092F\u092C\u0941\u0927\u0903 \u092A\u094D\u0930\u0924\u093F\u092A\u0926\u094D\u092F\u0924\u0947 \u0965\u0967\u096B\u0965</p><p class="trans">K\u0101ryonmukha\u1E25 prayatno ya\u1E25 kevala\u1E41 so&#39;tra lupyate\u0964<br> Tasmim\u0310llupte vilupto&#39;sm\u012Btyabudha\u1E25 pratipadyate \u096515\u0965</p><p>\u0422\u043E\u043B\u044C\u043A\u043E <em>(kevalam)</em> [\u0442\u043E] \u0443\u0441\u0438\u043B\u0438\u0435 <em>(prayatna\u1E25... sa\u1E25)</em>, \u043A\u043E\u0442\u043E\u0440\u043E\u0435 <em>(ya\u1E25)</em> \u043D\u0430\u043F\u0440\u0430\u0432\u043B\u0435\u043D\u043E <em>(unmukha\u1E25)</em> \u043D\u0430 \u0434\u0435\u0439\u0441\u0442\u0432\u0438\u0435 <em>(k\u0101rya)</em>, \u0438\u0441\u0447\u0435\u0437\u0430\u0435\u0442 <em>(lupyate)</em> \u0432 \u044D\u0442\u043E\u043C [\u0441\u043E\u0441\u0442\u043E\u044F\u043D\u0438\u0438 sam\u0101dhi] <em>(atra)</em><sup>1</sup>. \u041A\u043E\u0433\u0434\u0430 \u044D\u0442\u043E [\u0443\u0441\u0438\u043B\u0438\u0435] \u0438\u0441\u0447\u0435\u0437\u0430\u0435\u0442 <em>(tasmin lupte)</em>, [\u0442\u043E\u043B\u044C\u043A\u043E] \u0433\u043B\u0443\u043F\u0435\u0446 <em>(abudha\u1E25)</em> [\u043C\u043E\u0436\u0435\u0442] \u043F\u043E\u0434\u0443\u043C\u0430\u0442\u044C <em>(pratipadyate)</em>, \xAB\u042F \u0438\u0441\u0447\u0435\u0437\xBB <em>(vilupta\u1E25 asmi iti)</em>.</p><ol><li>\u0410\u0432\u0442\u043E\u0440 \u0438\u043C\u0435\u0435\u0442 \u0432 \u0432\u0438\u0434\u0443 sam\u0101dhi \u043F\u0443\u0441\u0442\u043E\u0442\u044B.</li></ol></div><div class="stanza"><a href="#s1.16" id="s1.16" class="num">1.16</a><p class="sans">\u0928 \u0924\u0941 \u092F\u094B\u093D\u0928\u094D\u0924\u0930\u094D\u092E\u0941\u0916\u094B \u092D\u093E\u0935\u0903 \u0938\u0930\u094D\u0935\u091C\u094D\u091E\u0924\u094D\u0935\u0917\u0941\u0923\u093E\u0938\u094D\u092A\u0926\u092E\u094D \u0964<br> \u0924\u0938\u094D\u092F \u0932\u094B\u092A\u0903 \u0915\u0926\u093E\u091A\u093F\u0924\u094D\u0938\u094D\u092F\u093E\u0926\u0928\u094D\u092F\u0938\u094D\u092F\u093E\u0928\u0941\u092A\u0932\u092E\u094D\u092D\u0928\u093E\u0924\u094D \u0965\u0967\u096C \u0965</p><p class="trans">Na tu yo&#39;ntarmukho bh\u0101va\u1E25 sarvaj\xF1atvagu\u1E47\u0101spadam\u0964<br> Tasya lopa\u1E25 kad\u0101citsy\u0101danyasy\u0101nupalambhan\u0101t \u096516\u0965</p><p>\u041D\u0438\u043A\u043E\u0433\u0434\u0430 \u043D\u0435 <em>(na tu... kad\u0101cid)</em> \u0431\u044B\u0432\u0430\u0435\u0442 <em>(sy\u0101t)</em> \u043F\u0440\u0435\u043A\u0440\u0430\u0449\u0435\u043D\u0438\u044F <em>(lopa\u1E25)</em> \u0442\u043E\u0433\u043E <em>(tasya)</em> \u0432\u043D\u0443\u0442\u0440\u0435\u043D\u043D\u0435\u0433\u043E <em>(antarmukha\u1E25)</em> \u0441\u043E\u0441\u0442\u043E\u044F\u043D\u0438\u044F <em>(bh\u0101va\u1E25)</em>, \u043A\u043E\u0442\u043E\u0440\u043E\u0435 <em>(ya\u1E25)</em> [\u044F\u0432\u043B\u044F\u0435\u0442\u0441\u044F] \u043E\u0431\u0438\u0442\u0435\u043B\u044C\u044E <em>(\u0101spadam)</em> \u043A\u0430\u0447\u0435\u0441\u0442\u0432\u0430 <em>(gu\u1E47a)</em> \u0432\u0441\u0435\u0437\u043D\u0430\u043D\u0438\u044F <em>(sarvaj\xF1atva)</em>, \u0438\u0437-\u0437\u0430 \u043D\u0435\u0432\u043E\u0441\u043F\u0440\u0438\u044F\u0442\u0438\u044F <em>(anupalambhan\u0101t)</em> \u0434\u0440\u0443\u0433\u043E\u0433\u043E <em>(anyasya)</em><sup>1</sup>.</p><ol><li>\u0422\u043E\u043B\u044C\u043A\u043E \u0428\u0438\u0432\u0430 \u044F\u0432\u043B\u044F\u0435\u0442\u0441\u044F \u0441\u0443\u0431\u044A\u0435\u043A\u0442\u043E\u043C, \u0438\u043B\u0438 \u0432\u043E\u0441\u043F\u0440\u0438\u043D\u0438\u043C\u0430\u044E\u0449\u0438\u043C, \u0438 \u043D\u0438\u043A\u0442\u043E \u0438\u043D\u043E\u0439. \u0415\u0441\u043B\u0438 \u0431\u044B \u0438 \u0441\u0443\u0449\u0435\u0441\u0442\u0432\u043E\u0432\u0430\u043B \u0434\u0440\u0443\u0433\u043E\u0439 \u0441\u0443\u0431\u044A\u0435\u043A\u0442, \u043D\u0430\u0431\u043B\u044E\u0434\u0430\u044E\u0449\u0438\u0439 \u0438\u0441\u0447\u0435\u0437\u043D\u043E\u0432\u0435\u043D\u0438\u0435 \u0428\u0438\u0432\u044B, \u0442\u043E \u043E\u043D \u0442\u043E\u0436\u0435 \u0431\u044B\u043B \u0431\u044B \u0428\u0438\u0432\u043E\u0439, \u0430 \u0437\u043D\u0430\u0447\u0438\u0442, \u0428\u0438\u0432\u0430 \u043D\u0435 \u043F\u0440\u0435\u043A\u0440\u0430\u0442\u0438\u043B \u0431\u044B \u0441\u0432\u043E\u0451 \u0441\u0443\u0449\u0435\u0441\u0442\u0432\u043E\u0432\u0430\u043D\u0438\u0435. \u0410 \u0435\u0441\u043B\u0438 \u043D\u0438\u043A\u0442\u043E \u043D\u0435 \u0432\u043E\u0441\u043F\u0440\u0438\u043D\u0438\u043C\u0430\u0435\u0442 \u043F\u0440\u0435\u043A\u0440\u0430\u0449\u0435\u043D\u0438\u044F \u0415\u0433\u043E \u0441\u0443\u0449\u0435\u0441\u0442\u0432\u043E\u0432\u0430\u043D\u0438\u044F, \u0442\u043E \u043A\u0430\u043A \u043E\u043D\u043E \u043C\u043E\u0436\u0435\u0442 \u0431\u044B\u0442\u044C \u0434\u043E\u043A\u0430\u0437\u0430\u043D\u043E? \u0428\u0438\u0432\u0430 \u2014 \u0432\u0441\u0435\u0433\u0434\u0430 \u0435\u0434\u0438\u043D\u0441\u0442\u0432\u0435\u043D\u043D\u044B\u0439 \u0441\u0443\u0431\u044A\u0435\u043A\u0442, \u043A\u043E\u0442\u043E\u0440\u044B\u0439 \u043D\u0435 \u043C\u043E\u0436\u0435\u0442 \u043F\u0440\u0435\u043A\u0440\u0430\u0442\u0438\u0442\u044C \u0441\u0443\u0449\u0435\u0441\u0442\u0432\u043E\u0432\u0430\u0442\u044C.</li></ol></div><div class="stanza"><a href="#s1.17" id="s1.17" class="num">1.17</a><p class="sans">\u0924\u0938\u094D\u092F\u094B\u092A\u0932\u092C\u094D\u0927\u093F\u0903 \u0938\u0924\u0924\u0902 \u0924\u094D\u0930\u093F\u092A\u0926\u093E\u0935\u094D\u092F\u092D\u093F\u091A\u093E\u0930\u093F\u0923\u0940 \u0964<br> \u0928\u093F\u0924\u094D\u092F\u0902 \u0938\u094D\u092F\u093E\u0924\u094D\u0938\u0941\u092A\u094D\u0930\u092C\u0941\u0926\u094D\u0927\u0938\u094D\u092F \u0924\u0926\u093E\u0926\u094D\u092F\u0928\u094D\u0924\u0947 \u092A\u0930\u0938\u094D\u092F \u0924\u0941 \u0965\u0967\u096D\u0965</p><p class="trans">Tasyopalabdhi\u1E25 satata\u1E41 tripad\u0101vyabhic\u0101ri\u1E47\u012B\u0964<br> Nitya\u1E41 sy\u0101tsuprabuddhasya tad\u0101dyante parasya tu \u096517\u0965</p><p>\u0412 \u0441\u043B\u0443\u0447\u0430\u0435 \u0441\u043E\u0432\u0435\u0440\u0448\u0435\u043D\u043D\u043E \u043F\u0440\u043E\u0431\u0443\u0436\u0434\u0451\u043D\u043D\u043E\u0433\u043E <em>(suprabuddhasya)</em> \u0432\u0441\u0435\u0433\u0434\u0430 <em>(nityam)</em> [\u0438] \u0431\u0435\u0441\u043F\u0440\u0435\u0440\u044B\u0432\u043D\u043E <em>(satatam)</em> \u043F\u0440\u043E\u0438\u0441\u0445\u043E\u0434\u0438\u0442 <em>(sy\u0101t)</em> \u0432\u043E\u0441\u043F\u0440\u0438\u044F\u0442\u0438\u0435 <em>(upalabdhi\u1E25)</em> \u0422\u043E\u0433\u043E --\u0412\u044B\u0441\u0448\u0435\u0433\u043E \u042F-- <em>(tasya)</em>, [\u0438 \u044D\u0442\u043E \u0432\u043E\u0441\u043F\u0440\u0438\u044F\u0442\u0438\u0435] \u043F\u043E\u0434\u0434\u0435\u0440\u0436\u0438\u0432\u0430\u0435\u0442\u0441\u044F <em>(avyabhic\u0101ri\u1E47\u012B)</em> [\u0432 \u0442\u0435\u0447\u0435\u043D\u0438\u0435] \u0442\u0440\u0451\u0445 <em>(tri)</em> \u0441\u043E\u0441\u0442\u043E\u044F\u043D\u0438\u0439 [\u0441\u043E\u0437\u043D\u0430\u043D\u0438\u044F] <em>(pada)</em>. \u0422\u0435\u043C \u043D\u0435 \u043C\u0435\u043D\u0435\u0435 <em>(tu)</em>, \u0432 \u0441\u043B\u0443\u0447\u0430\u0435 \u0434\u0440\u0443\u0433\u043E\u0433\u043E --\u043D\u0435 \u043F\u043E\u043B\u043D\u043E\u0441\u0442\u044C\u044E \u043F\u0440\u043E\u0431\u0443\u0436\u0434\u0451\u043D\u043D\u043E\u0433\u043E-- <em>(parasya)</em>, \u044D\u0442\u043E --\u0432\u043E\u0441\u043F\u0440\u0438\u044F\u0442\u0438\u0435 \u0412\u044B\u0441\u0448\u0435\u0433\u043E \u042F-- <em>(tad)</em> [\u043F\u0440\u043E\u0438\u0441\u0445\u043E\u0434\u0438\u0442 \u0442\u043E\u043B\u044C\u043A\u043E] \u0432 \u043D\u0430\u0447\u0430\u043B\u0435 <em>(\u0101di)</em> [\u0438] \u0432 \u043A\u043E\u043D\u0446\u0435 <em>(ante)</em> [\u043A\u0430\u0436\u0434\u043E\u0433\u043E \u0441\u043E\u0441\u0442\u043E\u044F\u043D\u0438\u044F \u0441\u043E\u0437\u043D\u0430\u043D\u0438\u044F].</p></div><div class="stanza"><a href="#s1.18" id="s1.18" class="num">1.18</a><p class="sans">\u091C\u094D\u091E\u093E\u0928\u091C\u094D\u091E\u0947\u092F\u0938\u094D\u0935\u0930\u0942\u092A\u093F\u0923\u094D\u092F\u093E \u0936\u0915\u094D\u0924\u094D\u092F\u093E \u092A\u0930\u092E\u092F\u093E \u092F\u0941\u0924\u0903 \u0964<br> \u092A\u0926\u0926\u094D\u0935\u092F\u0947 \u0935\u093F\u092D\u0941\u0930\u094D\u092D\u093E\u0924\u093F \u0924\u0926\u0928\u094D\u092F\u0924\u094D\u0930 \u0924\u0941 \u091A\u093F\u0928\u094D\u092E\u092F\u0903 \u0965\u0967\u096E\u0965</p><p class="trans">J\xF1\u0101naj\xF1eyasvar\u016Bpi\u1E47y\u0101 \u015Bakty\u0101 paramay\u0101 yuta\u1E25\u0964<br> Padadvaye vibhurbh\u0101ti tadanyatra tu cinmaya\u1E25 \u096518\u0965</p><p>\u0412\u0435\u0437\u0434\u0435\u0441\u0443\u0449\u0435\u0435 [\u0412\u044B\u0441\u0448\u0435\u0435 \u042F] <em>(vibhu\u1E25)</em> \u0441\u0438\u044F\u0435\u0442 <em>(bh\u0101ti)</em> \u0432 \u0434\u0432\u0443\u0445 <em>(dvaye)</em> \u0441\u043E\u0441\u0442\u043E\u044F\u043D\u0438\u044F\u0445 [\u0441\u043E\u0437\u043D\u0430\u043D\u0438\u044F: \u0432 \u0431\u043E\u0434\u0440\u0441\u0442\u0432\u043E\u0432\u0430\u043D\u0438\u0438 \u0438 \u0441\u043D\u0435] <em>(pada)</em>, \u0441\u043E\u043F\u0440\u043E\u0432\u043E\u0436\u0434\u0430\u0435\u043C\u043E\u0435 <em>(yuta\u1E25)</em> [\u0415\u0433\u043E] \u0412\u044B\u0441\u0448\u0435\u0439 --parama-- <em>(paramay\u0101)</em> \u0421\u0438\u043B\u043E\u0439 --\u015Bakti-- <em>(\u015Bakty\u0101)</em>, \u0447\u044C\u0435\u0439 \u043F\u0440\u0438\u0440\u043E\u0434\u043E\u0439 <em>(sva-r\u016Bpi\u1E47y\u0101)</em> [\u044F\u0432\u043B\u044F\u0435\u0442\u0441\u044F] \u0437\u043D\u0430\u043D\u0438\u0435 <em>(j\xF1\u0101na)</em> [\u0438] \u043F\u043E\u0437\u043D\u0430\u0432\u0430\u0435\u043C\u043E\u0435 <em>(j\xF1eya)</em>. \u0422\u0435\u043C \u043D\u0435 \u043C\u0435\u043D\u0435\u0435 <em>(tu)</em>, \u0432 \u0434\u0440\u0443\u0433\u043E\u043C [\u0441\u043E\u0441\u0442\u043E\u044F\u043D\u0438\u0438 \u0441\u043E\u0437\u043D\u0430\u043D\u0438\u044F] <em>(anyatra)</em> \u043F\u043E\u043C\u0438\u043C\u043E \u044D\u0442\u0438\u0445 [\u0434\u0432\u0443\u0445] <em>(tad)</em><sup>1</sup>, [\u041E\u043D \u043F\u0440\u043E\u044F\u0432\u043B\u044F\u0435\u0442\u0441\u044F \u0432 \u0432\u0438\u0434\u0435 \u0442\u043E\u043B\u044C\u043A\u043E] \u0421\u043E\u0437\u043D\u0430\u043D\u0438\u044F <em>(cit-maya\u1E25)</em>.</p><ol><li>\u0422\u043E \u0435\u0441\u0442\u044C \u0432 \u0433\u043B\u0443\u0431\u043E\u043A\u043E\u043C \u0441\u043D\u0435.</li></ol></div><div class="stanza"><a href="#s1.19" id="s1.19" class="num">1.19</a><p class="sans">\u0917\u0941\u0923\u093E\u0926\u093F\u0938\u094D\u092A\u0928\u094D\u0926\u0928\u093F\u0937\u094D\u092F\u0928\u094D\u0926\u093E\u0903 \u0938\u093E\u092E\u093E\u0928\u094D\u092F\u0938\u094D\u092A\u0928\u094D\u0926\u0938\u0902\u0936\u094D\u0930\u092F\u093E\u0924\u094D \u0964<br> \u0932\u092C\u094D\u0927\u093E\u0924\u094D\u092E\u0932\u093E\u092D\u093E\u0903 \u0938\u0924\u0924\u0902 \u0938\u094D\u092F\u0941\u0930\u094D\u091C\u094D\u091E\u0938\u094D\u092F\u093E\u092A\u0930\u093F\u092A\u0928\u094D\u0925\u093F\u0928\u0903 \u0965\u0967\u096F\u0965</p><p class="trans">Gu\u1E47\u0101dispandani\u1E63yand\u0101\u1E25 s\u0101m\u0101nyaspandasa\u1E41\u015Bray\u0101t\u0964<br> Labdh\u0101tmal\u0101bh\u0101\u1E25 satata\u1E41 syurj\xF1asy\u0101paripanthina\u1E25 \u096519\u0965</p><p>\u042D\u043C\u0430\u043D\u0430\u0446\u0438\u0438 <em>(ni\u1E63yand\u0101\u1E25)</em> \u0421\u043F\u0430\u043D\u0434\u044B <em>(spanda)</em>, \u043A\u043E\u0442\u043E\u0440\u044B\u0435 \u043D\u0430\u0447\u0438\u043D\u0430\u044E\u0442\u0441\u044F <em>(\u0101di)</em> \u0441 \u043A\u0430\u0447\u0435\u0441\u0442\u0432 Prak\u1E5Bti <em>(gu\u1E47a)</em> [\u0438] \u043F\u0440\u0438\u043E\u0431\u0440\u0435\u0442\u0430\u044E\u0442 <em>(labdha)</em> \u0441\u043E\u0431\u0441\u0442\u0432\u0435\u043D\u043D\u043E\u0435 <em>(\u0101tma)</em> \u0441\u0443\u0449\u0435\u0441\u0442\u0432\u043E\u0432\u0430\u043D\u0438\u0435 <em>(l\u0101bh\u0101\u1E25)</em>, \u043E\u043F\u0438\u0440\u0430\u044F\u0441\u044C <em>(sa\u1E41\u015Bray\u0101t)</em> \u043D\u0430 \u0443\u043D\u0438\u0432\u0435\u0440\u0441\u0430\u043B\u044C\u043D\u0443\u044E <em>(s\u0101m\u0101nya)</em> \u0421\u043F\u0430\u043D\u0434\u0443 <em>(spanda)</em>, \u043D\u0438\u043A\u043E\u0433\u0434\u0430 \u043D\u0435 \u043F\u0440\u0435\u043F\u044F\u0442\u0441\u0442\u0432\u0443\u044E\u0442 <em>(satatam syu\u1E25... aparipanthina\u1E25)</em> \u043F\u043E\u0437\u043D\u0430\u0432\u0448\u0435\u043C\u0443 [\u0412\u044B\u0441\u0448\u0435\u0435 \u042F] <em>(j\xF1\u0101sya)</em>.</p></div><div class="stanza"><a href="#s1.20" id="s1.20" class="num">1.20</a><p class="sans">\u0905\u092A\u094D\u0930\u092C\u0941\u0926\u094D\u0927\u0927\u093F\u092F\u0938\u094D\u0924\u094D\u0935\u0947\u0924\u0947 \u0938\u094D\u0935\u0938\u094D\u0925\u093F\u0924\u093F\u0938\u094D\u0925\u0917\u0928\u094B\u0926\u094D\u092F\u0924\u093E\u0903 \u0964<br> \u092A\u093E\u0924\u092F\u0928\u094D\u0924\u093F \u0926\u0941\u0930\u0941\u0924\u094D\u0924\u093E\u0930\u0947 \u0918\u094B\u0930\u0947 \u0938\u0902\u0938\u093E\u0930\u0935\u0930\u094D\u0924\u094D\u092E\u0928\u093F \u0965\u0968\u0966\u0965</p><p class="trans">Aprabuddhadhiyastvete svasthitisthaganodyat\u0101\u1E25\u0964<br> P\u0101tayanti durutt\u0101re ghore sa\u1E41s\u0101ravartmani \u096520\u0965</p><p>\u0422\u0435\u043C \u043D\u0435 \u043C\u0435\u043D\u0435\u0435 <em>(tu)</em>, \u044D\u0442\u0438 [\u0441\u0430\u043C\u044B\u0435 \u044D\u043C\u0430\u043D\u0430\u0446\u0438\u0438 \u0421\u043F\u0430\u043D\u0434\u044B] <em>(ete)</em>, \u0431\u0435\u0441\u043F\u0440\u0435\u0441\u0442\u0430\u043D\u043D\u043E \u0438 \u0443\u0441\u0435\u0440\u0434\u043D\u043E \u0442\u0440\u0443\u0434\u044F\u0441\u044C \u043D\u0430\u0434 <em>(udyat\u0101\u1E25)</em> \u0441\u043E\u043A\u0440\u044B\u0442\u0438\u0435\u043C <em>(sthagana)</em> \u0438\u0445 --\u043D\u0435 \u043F\u0440\u043E\u0431\u0443\u0436\u0434\u0451\u043D\u043D\u044B\u0445-- <em>(sva)</em> [\u0438\u0441\u0442\u0438\u043D\u043D\u043E\u0439] \u043F\u0440\u0438\u0440\u043E\u0434\u044B <em>(sthiti)</em>, \u0437\u0430\u0441\u0442\u0430\u0432\u043B\u044F\u044E\u0442 \u043B\u0438\u0447\u043D\u043E\u0441\u0442\u0435\u0439 \u0441 \u043D\u0435 \u043F\u0440\u043E\u0431\u0443\u0436\u0434\u0451\u043D\u043D\u044B\u043C \u0438\u043D\u0442\u0435\u043B\u043B\u0435\u043A\u0442\u043E\u043C \u043E\u043F\u0443\u0441\u043A\u0430\u0442\u044C\u0441\u044F <em>(aprabuddha-dhiya\u1E25... p\u0101tayanti)</em> \u0434\u043E \u0443\u0436\u0430\u0441\u043D\u043E\u0433\u043E <em>(ghore)</em> \u043F\u0443\u0442\u0438 <em>(vartmani)</em> \u0442\u0440\u0430\u043D\u0441\u043C\u0438\u0433\u0440\u0430\u0446\u0438\u0438 <em>(sa\u1E41s\u0101ra)</em>, \u0441 \u043A\u043E\u0442\u043E\u0440\u043E\u0433\u043E \u0442\u0440\u0443\u0434\u043D\u043E \u0441\u043E\u0439\u0442\u0438 <em>(durutt\u0101re)</em>.</p></div><div class="stanza"><a href="#s1.21" id="s1.21" class="num">1.21</a><p class="sans">\u0905\u0924\u0903 \u0938\u0924\u0924\u092E\u0941\u0926\u094D\u092F\u0941\u0915\u094D\u0924\u0903 \u0938\u094D\u092A\u0928\u094D\u0926\u0924\u0924\u094D\u0924\u094D\u0935\u0935\u093F\u0935\u093F\u0915\u094D\u0924\u092F\u0947 \u0964<br> \u091C\u093E\u0917\u094D\u0930\u0926\u0947\u0935 \u0928\u093F\u091C\u0902 \u092D\u093E\u0935\u092E\u091A\u093F\u0930\u0947\u0923\u093E\u0927\u093F\u0917\u091A\u094D\u091B\u0924\u093F \u0965\u0968\u0967 \u0965</p><p class="trans">Ata\u1E25 satatamudyukta\u1E25 spandatattvaviviktaye\u0964<br> J\u0101gradeva nija\u1E41 bh\u0101vamacire\u1E47\u0101dhigacchati \u096521\u0965</p><p>\u041F\u043E \u044D\u0442\u043E\u0439 \u043F\u0440\u0438\u0447\u0438\u043D\u0435 <em>(atas)</em> \u0442\u043E\u0442, \u043A\u0442\u043E \u0432\u0441\u0435\u0433\u0434\u0430 <em>(satatam)</em> \u0433\u043E\u0442\u043E\u0432 <em>(udyukta\u1E25)</em> \u043A \u0440\u0430\u0437\u043B\u0438\u0447\u0435\u043D\u0438\u044E <em>(viviktaye)</em> \u043F\u0440\u0438\u043D\u0446\u0438\u043F\u0430 <em>(tattva)</em> \u0421\u043F\u0430\u043D\u0434\u044B <em>(spanda)</em>, \u0431\u044B\u0441\u0442\u0440\u043E <em>(acire\u1E47a)</em> \u0434\u043E\u0441\u0442\u0438\u0433\u0430\u0435\u0442 <em>(adhigacchati)</em> \u0441\u0432\u043E\u0435\u0439 <em>(nijam)</em> [\u0438\u0441\u0442\u0438\u043D\u043D\u043E\u0439] \u043F\u0440\u0438\u0440\u043E\u0434\u044B <em>(bh\u0101vam)</em> [\u0434\u0430\u0436\u0435 \u0432\u043E \u0432\u0440\u0435\u043C\u044F] \u0431\u043E\u0434\u0440\u0441\u0442\u0432\u043E\u0432\u0430\u043D\u0438\u044F <em>(j\u0101grat eva)</em>.</p></div><div class="stanza"><a href="#s1.22" id="s1.22" class="num">1.22</a><p class="sans">\u0905\u0924\u093F\u0915\u094D\u0930\u0941\u0926\u094D\u0927\u0903 \u092A\u094D\u0930\u0939\u0943\u0937\u094D\u091F\u094B \u0935\u093E \u0915\u093F\u0902 \u0915\u0930\u094B\u092E\u0940\u0924\u093F \u0935\u093E \u092E\u0943\u0936\u0928\u094D \u0964<br> \u0927\u093E\u0935\u0928\u094D\u0935\u093E \u092F\u0924\u094D\u092A\u0926\u0902 \u0917\u091A\u094D\u091B\u0947\u0924\u094D\u0924\u0924\u094D\u0930 \u0938\u094D\u092A\u0928\u094D\u0926\u0903 \u092A\u094D\u0930\u0924\u093F\u0937\u094D\u0920\u093F\u0924\u0903 \u0965\u0968\u0968\u0965</p><p class="trans">Atikruddha\u1E25 prah\u1E5B\u1E63\u1E6Do v\u0101 ki\u1E41 karom\u012Bti v\u0101 m\u1E5B\u015Ban\u0964<br> Dh\u0101vanv\u0101 yatpada\u1E41 gacchettatra spanda\u1E25 prati\u1E63\u1E6Dhita\u1E25 \u096522\u0965</p><p>\u0421\u043F\u0430\u043D\u0434\u0430 <em>(spanda\u1E25)</em> \u043F\u0440\u043E\u0447\u043D\u043E \u0443\u043A\u043E\u0440\u0435\u043D\u0435\u043D\u0430 <em>(prati\u1E63\u1E6Dhita\u1E25)</em> \u0432 \u0442\u043E\u043C <em>(tatra)</em> \u0441\u043E\u0441\u0442\u043E\u044F\u043D\u0438\u0438 <em>(padam)</em>, \u043A\u043E\u0442\u043E\u0440\u043E\u0435 <em>(yad)</em> \u043F\u0440\u043E\u044F\u0432\u043B\u044F\u0435\u0442\u0441\u044F <em>(gacchet)</em> [\u0432 \u0447\u0435\u043B\u043E\u0432\u0435\u043A\u0435, \u043A\u043E\u0433\u0434\u0430 \u043E\u043D] \u043A\u0440\u0430\u0439\u043D\u0435 \u0437\u043E\u043B <em>(atikruddha\u1E25)</em>, \u0447\u0440\u0435\u0437\u043C\u0435\u0440\u043D\u043E \u0434\u043E\u0432\u043E\u043B\u0435\u043D \u0438\u043B\u0438 \u0432\u043E\u0441\u0442\u043E\u0440\u0436\u0435\u043D <em>(prah\u1E5B\u1E63\u1E6Da\u1E25)</em>, \u0440\u0430\u0437\u043C\u044B\u0448\u043B\u044F\u0435\u0442 <em>(m\u1E5B\u015Ban)</em>, \xAB\u0427\u0442\u043E <em>(kim)</em> \u043C\u043D\u0435 \u0434\u0435\u043B\u0430\u0442\u044C <em>(karomi iti)</em>?\xBB \u0438\u043B\u0438 <em>(v\u0101.. v\u0101... v\u0101)</em> \u0443\u0431\u0435\u0433\u0430\u0435\u0442 [\u043E\u0442 \u0441\u043C\u0435\u0440\u0442\u0435\u043B\u044C\u043D\u043E\u0439 \u043E\u043F\u0430\u0441\u043D\u043E\u0441\u0442\u0438] <em>(dh\u0101van)</em>.</p></div><div class="stanza"><a href="#s1.23" id="s1.23" class="num">1.23</a><p class="sans">\u092F\u093E\u092E\u0935\u0938\u094D\u0925\u093E\u0902 \u0938\u092E\u093E\u0932\u092E\u094D\u092C\u094D\u092F \u092F\u0926\u092F\u0902 \u092E\u092E \u0935\u0915\u094D\u0937\u094D\u092F\u0924\u093F \u0964<br> \u0924\u0926\u0935\u0936\u094D\u092F\u0902 \u0915\u0930\u093F\u0937\u094D\u092F\u0947\u093D\u0939\u092E\u093F\u0924\u093F \u0938\u0919\u094D\u0915\u0932\u094D\u092A\u094D\u092F \u0924\u093F\u0937\u094D\u0920\u0924\u093F \u0965\u0968\u0969\u0965</p><p class="trans">Y\u0101mavasth\u0101\u1E41 sam\u0101lambya yadaya\u1E41 mama vak\u1E63yati\u0964<br> Tadava\u015Bya\u1E41 kari\u1E63ye&#39;hamiti sa\u1E45kalpya ti\u1E63\u1E6Dhati \u096523\u0965</p><p>\u0423\u0445\u0432\u0430\u0442\u0438\u0432\u0448\u0438\u0441\u044C <em>(sam\u0101lambya)</em> \u0437\u0430 \u0442\u043E <em>(y\u0101m)</em> [\u0432\u044B\u0441\u0448\u0435\u0435] \u0441\u043E\u0441\u0442\u043E\u044F\u043D\u0438\u0435 [\u0421\u043F\u0430\u043D\u0434\u044B] <em>(avasth\u0101m)</em>, [\u0432\u0435\u043B\u0438\u043A\u0438\u0439 \u0419\u043E\u0433] \u043E\u0441\u0442\u0430\u0451\u0442\u0441\u044F \u043D\u0435\u043F\u0440\u0435\u043A\u043B\u043E\u043D\u043D\u044B\u043C <em>(ti\u1E63\u1E6Dhati)</em>, \u0440\u0430\u0437\u043C\u044B\u0448\u043B\u044F\u044F [\u0442\u0430\u043A:] <em>(sa\u1E45kalpya)</em> \xAB\u0427\u0442\u043E \u0431\u044B <em>(yad)</em> \u044D\u0442\u043E [\u0412\u044B\u0441\u0448\u0435\u0435 \u042F] <em>(ayam)</em> \u043C\u043D\u0435 <em>(mama)</em> \u043D\u0438 \u0441\u043A\u0430\u0437\u0430\u043B\u043E <em>(vak\u1E63yati)</em>, \u0442\u043E <em>(tad)</em> \u044F <em>(aham)</em> \u043E\u0431\u044F\u0437\u0430\u0442\u0435\u043B\u044C\u043D\u043E <em>(ava\u015Byam... iti)</em> \u0441\u0434\u0435\u043B\u0430\u044E <em>(kari\u1E63ye)</em>\xBB.</p></div><div class="stanza"><a href="#s1.24" id="s1.24" class="num">1.24</a><p class="sans">\u0924\u093E\u092E\u093E\u0936\u094D\u0930\u093F\u0924\u094D\u092F\u094B\u0930\u094D\u0927\u094D\u0935\u092E\u093E\u0930\u094D\u0917\u0947\u0923 \u091A\u0928\u094D\u0926\u094D\u0930\u0938\u0942\u0930\u094D\u092F\u093E\u0935\u0941\u092D\u093E\u0935\u092A\u093F \u0964<br> \u0938\u094C\u0937\u0941\u092E\u094D\u0928\u0947\u093D\u0927\u094D\u0935\u0928\u094D\u092F\u0938\u094D\u0924\u092E\u093F\u0924\u094B \u0939\u093F\u0924\u094D\u0935\u093E \u092C\u094D\u0930\u0939\u094D\u092E\u093E\u0923\u094D\u0921\u0917\u094B\u091A\u0930\u092E\u094D \u0965\u0968\u096A\u0965</p><p class="trans">T\u0101m\u0101\u015Brityordhvam\u0101rge\u1E47a candras\u016Bry\u0101vubh\u0101vapi\u0964<br> Sau\u1E63umne&#39;dhvanyastamito hitv\u0101 brahm\u0101\u1E47\u1E0Dagocaram \u096524\u0965</p><p>\u041D\u0430\u0445\u043E\u0434\u044F \u0443\u0431\u0435\u0436\u0438\u0449\u0435 <em>(\u0101\u015Britya)</em> \u0432 \u0442\u043E\u043C [\u0432\u044B\u0441\u0448\u0435\u043C \u0441\u043E\u0441\u0442\u043E\u044F\u043D\u0438\u0438 \u0421\u043F\u0430\u043D\u0434\u044B] <em>(t\u0101m)</em>, \u043E\u0431\u0430 <em>(ubhau)</em> \u043B\u0443\u043D\u0430 --ap\u0101na-- <em>(candra)</em><sup>1</sup> [\u0438] \u0441\u043E\u043B\u043D\u0446\u0435 --pr\u0101\u1E47a--<em>(s\u016Bryau api)</em><sup>2</sup>, [\u043F\u043E\u0434\u043D\u0438\u043C\u0430\u044F\u0441\u044C] \u043F\u043E \u0432\u043E\u0441\u0445\u043E\u0434\u044F\u0449\u0435\u043C\u0443 <em>(\u016Brdhva)</em> \u043F\u0443\u0442\u0438 <em>(m\u0101rge\u1E47a)</em>, \u0440\u0430\u0441\u0442\u0432\u043E\u0440\u044F\u044E\u0442\u0441\u044F <em>(astam ita\u1E25)</em> \u0432 \u043A\u0430\u043D\u0430\u043B\u0435 <em>(adhvani)</em> su\u1E63umn\u0101 <em>(sau\u1E63umne)</em> [\u0438 \u0437\u0430\u0442\u0435\u043C] \u043F\u043E\u043A\u0438\u0434\u0430\u044E\u0442 <em>(hitv\u0101)</em> \u0441\u0444\u0435\u0440\u0443 <em>(gocaram)</em> \u044F\u0439\u0446\u0430 \u0411\u0440\u0430\u0445\u043C\u044B <em>(brahm\u0101\u1E47\u1E0Da)</em><sup>3</sup>.</p><ol><li><p>Ap\u0101na \u2014 \u044D\u0442\u043E \u0442\u0430 \u0436\u0438\u0437\u043D\u0435\u043D\u043D\u0430\u044F \u044D\u043D\u0435\u0440\u0433\u0438\u044F, \u043A\u043E\u0442\u043E\u0440\u0430\u044F \u0432\u0445\u043E\u0434\u0438\u0442 \u0432 \u0442\u0435\u043B\u043E \u0447\u0435\u0440\u0435\u0437 \u0432\u0434\u043E\u0445.</p></li><li><p>Pr\u0101\u1E47a \u0432 \u044D\u0442\u043E\u043C \u043A\u043E\u043D\u0442\u0435\u043A\u0441\u0442\u0435 \u2014 \u044D\u0442\u043E \u0442\u0430 \u0436\u0438\u0437\u043D\u0435\u043D\u043D\u0430\u044F \u044D\u043D\u0435\u0440\u0433\u0438\u044F, \u043A\u043E\u0442\u043E\u0440\u0430\u044F \u043F\u043E\u043A\u0438\u0434\u0430\u0435\u0442 \u0442\u0435\u043B\u043E \u043F\u0440\u0438 \u0432\u044B\u0434\u043E\u0445\u0435.</p></li><li><p>Brahm\u0101\u1E47\u1E0Da, \u0438\u043B\u0438 \u044F\u0439\u0446\u043E \u0411\u0440\u0430\u0445\u043C\u044B, \u043E\u0431\u044B\u0447\u043D\u043E \u0441\u0438\u043C\u0432\u043E\u043B\u0438\u0437\u0438\u0440\u0443\u0435\u0442 \u043C\u0430\u043A\u0440\u043E\u043A\u043E\u0441\u043C, \u043D\u043E \u0432 \u044D\u0442\u043E\u043C \u043A\u043E\u043D\u0442\u0435\u043A\u0441\u0442\u0435, \u044D\u0442\u043E\u0442 \u0442\u0435\u0440\u043C\u0438\u043D \u0441\u043B\u0435\u0434\u0443\u0435\u0442 \u043F\u043E\u043D\u0438\u043C\u0430\u0442\u044C \u043A\u0430\u043A \xAB\u0442\u0435\u043B\u043E \u0438 brahmarandhra\xBB. Brahmarandhra \u2014 \u044D\u0442\u043E \u043E\u0442\u0432\u0435\u0440\u0441\u0442\u0438\u0435 \u0411\u0440\u0430\u0445\u043C\u044B, \u043A\u043E\u0442\u043E\u0440\u043E\u0435 \u043D\u0430\u0445\u043E\u0434\u0438\u0442\u0441\u044F \u0432 sahasr\u0101racakra, \u0432 \u043C\u0430\u043A\u0443\u0448\u043A\u0435 \u0433\u043E\u043B\u043E\u0432\u044B.</p></li></ol></div><div class="stanza"><a href="#s1.25" id="s1.25" class="num">1.25</a><p class="sans">\u0924\u0926\u093E \u0924\u0938\u094D\u092E\u093F\u0928\u094D\u092E\u0939\u093E\u0935\u094D\u092F\u094B\u092E\u094D\u0928\u093F \u092A\u094D\u0930\u0932\u0940\u0928\u0936\u0936\u093F\u092D\u093E\u0938\u094D\u0915\u0930\u0947 \u0964<br> \u0938\u094C\u0937\u0941\u092A\u094D\u0924\u092A\u0926\u0935\u0928\u094D\u092E\u0942\u0922\u0903 \u092A\u094D\u0930\u092C\u0941\u0926\u094D\u0927\u0903 \u0938\u094D\u092F\u093E\u0926\u0928\u093E\u0935\u0943\u0924\u0903 \u0965\u0968\u096B\u0965</p><p class="trans">Tad\u0101 tasminmah\u0101vyomni pral\u012Bna\u015Ba\u015Bibh\u0101skare\u0964<br> Sau\u1E63uptapadavanm\u016B\u1E0Dha\u1E25 prabuddha\u1E25 sy\u0101dan\u0101v\u1E5Bta\u1E25 \u096525\u0965</p><p>\u0417\u0430\u0442\u0435\u043C <em>(tad\u0101)</em>, \u043B\u0443\u043D\u0430 --ap\u0101na-- <em>(\u015Ba\u015Bi)</em> [\u0438] \u0441\u043E\u043B\u043D\u0446\u0435 --pr\u0101\u1E47a-- <em>(bh\u0101skare)</em> \u0432\u043D\u043E\u0432\u044C \u0440\u0430\u0441\u0442\u0432\u043E\u0440\u044F\u044E\u0442\u0441\u044F <em>(pral\u012Bna)</em> \u0432 \u0442\u043E\u043C <em>(tasmin)</em> \u0412\u0435\u043B\u0438\u043A\u043E\u043C <em>(mah\u0101)</em> \u042D\u0444\u0438\u0440\u0435 <em>(vyomni)</em>. [\u0414\u043B\u044F \u0447\u0430\u0441\u0442\u0438\u0447\u043D\u043E \u043F\u0440\u043E\u0431\u0443\u0436\u0434\u0451\u043D\u043D\u043E\u0433\u043E \u044D\u0442\u043E] \u043F\u043E\u0434\u043E\u0431\u043D\u043E <em>(vat)</em> \u0441\u043E\u0441\u0442\u043E\u044F\u043D\u0438\u044E <em>(pada)</em> \u0433\u043B\u0443\u0431\u043E\u043A\u043E\u0433\u043E \u0441\u043D\u0430 <em>(sau\u1E63upta)</em>, [\u043F\u043E\u044D\u0442\u043E\u043C\u0443] \u043E\u043D \u043D\u0430\u0445\u043E\u0434\u0438\u0442\u0441\u044F <em>(sy\u0101t)</em> \u0432 \u043E\u0446\u0435\u043F\u0435\u043D\u0435\u043D\u0438\u0438 <em>(m\u016B\u1E0Dha\u1E25)</em>. [\u0422\u0435\u043C \u043D\u0435 \u043C\u0435\u043D\u0435\u0435, \u0419\u043E\u0433,] \u043D\u0435 \u043F\u043E\u043A\u0440\u044B\u0442\u044B\u0439 [\u0442\u044C\u043C\u043E\u0439 \u043D\u0435\u0432\u0435\u0436\u0435\u0441\u0442\u0432\u0430] <em>(an\u0101v\u1E5Bta\u1E25)</em>, \u043E\u0441\u0442\u0430\u0451\u0442\u0441\u044F <em>(sy\u0101t)</em> \u043F\u0440\u043E\u0431\u0443\u0436\u0434\u0451\u043D\u043D\u044B\u043C <em>(prabuddha\u1E25)</em> [\u0432 \u044D\u0442\u043E\u043C \u0441\u043E\u0441\u0442\u043E\u044F\u043D\u0438\u0438].</p></div><h2 id="\u0447\u0430\u0441\u0442\u044C-ii-sahajavidyodaya" tabindex="-1">\u0427\u0430\u0441\u0442\u044C II: Sahajavidyodaya <a class="header-anchor" href="#\u0447\u0430\u0441\u0442\u044C-ii-sahajavidyodaya" aria-hidden="true">#</a></h2><p><strong>\u041F\u043E\u044F\u0432\u043B\u0435\u043D\u0438\u0435 \u0435\u0441\u0442\u0435\u0441\u0442\u0432\u0435\u043D\u043D\u043E\u0433\u043E \u0437\u043D\u0430\u043D\u0438\u044F</strong></p><div class="stanza"><a href="#s2.1" id="s2.1" class="num">2.1</a><p class="sans">\u0924\u0926\u093E\u0915\u094D\u0930\u092E\u094D\u092F \u092C\u0932\u0902 \u092E\u0928\u094D\u0924\u094D\u0930\u093E\u0903 \u0938\u0930\u094D\u0935\u091C\u094D\u091E\u092C\u0932\u0936\u093E\u0932\u093F\u0928\u0903 \u0964<br> \u092A\u094D\u0930\u0935\u0930\u094D\u0924\u0928\u094D\u0924\u0947\u093D\u0927\u093F\u0915\u093E\u0930\u093E\u092F \u0915\u0930\u0923\u093E\u0928\u0940\u0935 \u0926\u0947\u0939\u093F\u0928\u093E\u092E\u094D \u0965\u0967\u0965</p><p class="trans">Tad\u0101kramya bala\u1E41 mantr\u0101\u1E25 sarvaj\xF1abala\u015B\u0101lina\u1E25\u0964<br> Pravartante&#39;dhik\u0101r\u0101ya kara\u1E47\u0101n\u012Bva dehin\u0101m \u09651\u0965</p><p>\u0423\u0445\u0432\u0430\u0442\u044B\u0432\u0430\u044F\u0441\u044C <em>(\u0101kramya)</em> \u0437\u0430 \u044D\u0442\u0443 <em>(tad)</em> \u041C\u043E\u0449\u044C <em>(balam)</em>, \u041C\u0430\u043D\u0442\u0440\u044B <em>(mantr\u0101\u1E25)</em>, \u0438\u0441\u043F\u043E\u043B\u043D\u0435\u043D\u043D\u044B\u0435 <em>(\u015B\u0101lina\u1E25)</em> \u0432\u0441\u0435\u0437\u043D\u0430\u044E\u0449\u0435\u0439 <em>(sarvaj\xF1a)</em> \u0441\u0438\u043B\u044B <em>(bala)</em>, \u043F\u0440\u043E\u0434\u043E\u043B\u0436\u0430\u044E\u0442 <em>(pravartante)</em> \u0432\u044B\u043F\u043E\u043B\u043D\u044F\u0442\u044C \u0441\u0432\u043E\u0438 [\u0441\u043E\u043E\u0442\u0432\u0435\u0442\u0441\u0442\u0432\u0443\u044E\u0449\u0438\u0435] \u043E\u0431\u044F\u0437\u0430\u043D\u043D\u043E\u0441\u0442\u0438 <em>(adhik\u0101r\u0101ya)</em> [\u0432 \u043E\u0442\u043D\u043E\u0448\u0435\u043D\u0438\u0438 \u0432\u043E\u043F\u043B\u043E\u0449\u0451\u043D\u043D\u044B\u0445 \u0441\u0443\u0449\u0435\u0441\u0442\u0432], \u043F\u043E\u0434\u043E\u0431\u043D\u043E \u0442\u043E\u043C\u0443 \u043A\u0430\u043A <em>(iva)</em> \u0441\u0438\u043B\u044B \u0432\u043E\u0441\u043F\u0440\u0438\u044F\u0442\u0438\u044F \u0438 \u0434\u0435\u0439\u0441\u0442\u0432\u0438\u044F <em>(kara\u1E47\u0101ni)</em> [\u044D\u0442\u0438\u0445 \u0441\u0430\u043C\u044B\u0445] \u0432\u043E\u043F\u043B\u043E\u0449\u0451\u043D\u043D\u044B\u0445 \u0441\u0443\u0449\u0435\u0441\u0442\u0432 <em>(dehin\u0101m)</em> [\u043F\u0440\u043E\u0434\u043E\u043B\u0436\u0430\u044E\u0442 \u0432\u044B\u043F\u043E\u043B\u043D\u044F\u0442\u044C \u0441\u0432\u043E\u0438 \u0444\u0443\u043D\u043A\u0446\u0438\u0438, \u0443\u0445\u0432\u0430\u0442\u044B\u0432\u0430\u044F\u0441\u044C \u0437\u0430 \u044D\u0442\u0443 \u0436\u0435 \u0421\u0438\u043B\u0443].</p></div><div class="stanza"><a href="#s2.2" id="s2.2" class="num">2.2</a><p class="sans">\u0924\u0924\u094D\u0930\u0948\u0935 \u0938\u092E\u094D\u092A\u094D\u0930\u0932\u0940\u092F\u0928\u094D\u0924\u0947 \u0936\u093E\u0928\u094D\u0924\u0930\u0942\u092A\u093E \u0928\u093F\u0930\u091E\u094D\u091C\u0928\u093E\u0903 \u0964<br> \u0938\u0939\u093E\u0930\u093E\u0927\u0915\u091A\u093F\u0924\u094D\u0924\u0947\u0928 \u0924\u0947\u0928\u0948\u0924\u0947 \u0936\u093F\u0935\u0927\u0930\u094D\u092E\u093F\u0923\u0903 \u0965\u0968\u0965</p><p class="trans">Tatraiva sampral\u012Byante \u015B\u0101ntar\u016Bp\u0101 nira\xF1jan\u0101\u1E25\u0964<br> Sah\u0101r\u0101dhakacittena tenaite \u015Bivadharmi\u1E47a\u1E25 \u09652\u0965</p><p>[\u041C\u0430\u043D\u0442\u0440\u044B,] \u0447\u044C\u0451 \u043D\u0430\u0437\u043D\u0430\u0447\u0435\u043D\u0438\u0435 [\u043D\u0430 \u0440\u043E\u043B\u044C \u043E\u043F\u0440\u0435\u0434\u0435\u043B\u0451\u043D\u043D\u044B\u0445 \u0431\u043E\u0436\u0435\u0441\u0442\u0432] \u0437\u0430\u043A\u043E\u043D\u0447\u0438\u043B\u043E\u0441\u044C <em>(\u015B\u0101ntar\u016Bp\u0101\u1E25)</em>, \u043B\u0438\u0448\u0435\u043D\u043D\u044B\u0435 \u043E\u0433\u0440\u0430\u043D\u0438\u0447\u0435\u043D\u0438\u044F \u0432 \u0432\u0438\u0434\u0435 \u0441\u043B\u0443\u0436\u0431\u044B <em>(nira\xF1jan\u0101\u1E25)</em>, \u043F\u043E\u0433\u043B\u043E\u0449\u0430\u044E\u0442\u0441\u044F <em>(sampral\u012Byante)</em> \u0442\u043E\u0439 [\u0421\u043F\u0430\u043D\u0434\u043E\u0439] <em>(tatra eva)</em> \u0432\u043C\u0435\u0441\u0442\u0435 <em>(saha)</em> \u0441 \u0443\u043C\u043E\u043C <em>(cittena)</em> \u043F\u0440\u0435\u0434\u0430\u043D\u043D\u043E\u0433\u043E <em>(\u0101r\u0101dhaka)</em>. \u041F\u043E\u044D\u0442\u043E\u043C\u0443 <em>(tena)</em>, \u044D\u0442\u0438 [\u041C\u0430\u043D\u0442\u0440\u044B] <em>(ete)</em> \u043E\u0431\u043B\u0430\u0434\u0430\u044E\u0442 \u043F\u0440\u0438\u0440\u043E\u0434\u043E\u0439 <em>(dharmi\u1E47a\u1E25)</em> \u0428\u0438\u0432\u044B <em>(\u015Biva)</em>.</p></div><div class="stanza"><a href="#s2.3-4" id="s2.3-4" class="num">2.3-4</a><p class="sans">\u092F\u0938\u094D\u092E\u093E\u0924\u094D\u0938\u0930\u094D\u0935\u092E\u092F\u094B \u091C\u0940\u0935\u0903 \u0938\u0930\u094D\u0935\u092D\u093E\u0935\u0938\u092E\u0941\u0926\u094D\u092D\u0935\u093E\u0924\u094D \u0964<br> \u0924\u0924\u094D\u0938\u0902\u0935\u0947\u0926\u0928\u0930\u0942\u092A\u0947\u0923 \u0924\u093E\u0926\u093E\u0924\u094D\u092E\u094D\u092F\u092A\u094D\u0930\u0924\u093F\u092A\u0924\u094D\u0924\u093F\u0924\u0903 \u0965\u0969 \u0965</p><p class="sans">\u0924\u0938\u094D\u092E\u093E\u091A\u094D\u091B\u092C\u094D\u0926\u093E\u0930\u094D\u0925\u091A\u093F\u0928\u094D\u0924\u093E\u0938\u0941 \u0928 \u0938\u093E\u0935\u0938\u094D\u0925\u093E \u0928 \u092F\u093E \u0936\u093F\u0935\u0903 \u0964<br> \u092D\u094B\u0915\u094D\u0924\u0948\u0935 \u092D\u094B\u0917\u094D\u092F\u092D\u093E\u0935\u0947\u0928 \u0938\u0926\u093E \u0938\u0930\u094D\u0935\u0924\u094D\u0930 \u0938\u0902\u0938\u094D\u0925\u093F\u0924\u0903 \u0965\u096A\u0965</p><p class="trans">Yasm\u0101tsarvamayo j\u012Bva\u1E25 sarvabh\u0101vasamudbhav\u0101t\u0964<br> Tatsa\u1E41vedanar\u016Bpe\u1E47a t\u0101d\u0101tmyapratipattita\u1E25 \u09653\u0965</p><p class="trans">Tasm\u0101cchabd\u0101rthacint\u0101su na s\u0101vasth\u0101 na y\u0101 \u015Biva\u1E25\u0964<br> Bhoktaiva bhogyabh\u0101vena sad\u0101 sarvatra sa\u1E41sthita\u1E25 \u09654\u0965</p><p>\u041F\u043E\u0441\u043A\u043E\u043B\u044C\u043A\u0443 <em>(yasm\u0101t)</em> \u0438\u043D\u0434\u0438\u0432\u0438\u0434\u0443\u0430\u043B\u044C\u043D\u0430\u044F \u0434\u0443\u0448\u0430 <em>(j\u012Bva\u1E25)</em> \u0438\u0434\u0435\u043D\u0442\u0438\u0447\u043D\u0430 <em>(maya\u1E25)</em> \u0432\u0441\u0435\u043C\u0443 <em>(sarva)</em>, \u0442\u0430\u043A \u043A\u0430\u043A \u0432\u0441\u0435 \u0441\u0443\u0449\u0435\u0441\u0442\u0432\u0430 \u043F\u0440\u043E\u0438\u0441\u0445\u043E\u0434\u044F\u0442 <em>(sarva-bh\u0101va-samudbhav\u0101t)</em> [\u0438\u0437 \u043D\u0435\u0451], \u043E\u043D\u0430 \u043E\u0449\u0443\u0449\u0430\u0435\u0442 <em>(pratipattita\u1E25)</em> \u0442\u043E\u0436\u0434\u0435\u0441\u0442\u0432\u0435\u043D\u043D\u043E\u0441\u0442\u044C <em>(t\u0101d\u0101tmya)</em> [\u0432\u0441\u0435\u043C \u0438\u043C] \u0438\u0437-\u0437\u0430 [\u0435\u0451] \u0437\u043D\u0430\u043D\u0438\u044F <em>(sa\u1E41vedanar\u016Bpe\u1E47a)</em> \u0438\u0445 \u0432\u0441\u0435\u0445 <em>(tad)</em><sup>1</sup>, \u043F\u043E\u044D\u0442\u043E\u043C\u0443 <em>(tasm\u0101t)</em>, \u043D\u0435 \u0441\u0443\u0449\u0435\u0441\u0442\u0432\u0443\u0435\u0442 <em>(na)</em> \u0441\u043E\u0441\u0442\u043E\u044F\u043D\u0438\u044F <em>(s\u0101 avasth\u0101)</em>, \u043A\u043E\u0442\u043E\u0440\u043E\u0435 <em>(y\u0101)</em> \u043D\u0435 \u044F\u0432\u043B\u044F\u043B\u043E\u0441\u044C \u0431\u044B <em>(na)</em> \u0428\u0438\u0432\u043E\u0439 <em>(\u015Biva\u1E25)</em>, [\u0431\u0443\u0434\u044C \u0442\u043E] \u0441\u043B\u043E\u0432\u043E <em>(\u015Babda)</em>, \u043E\u0431\u044A\u0435\u043A\u0442 <em>(artha)</em> [\u0438\u043B\u0438] \u043C\u044B\u0441\u043B\u044C --cint\u0101-- <em>(cint\u0101su)</em>. \u0421\u0430\u043C <em>(eva)</em> \u0432\u043E\u0441\u043F\u0440\u0438\u043D\u0438\u043C\u0430\u044E\u0449\u0438\u0439 <em>(bhokt\u0101)</em> \u0432\u0441\u0435\u0433\u0434\u0430 <em>(sad\u0101)</em> [\u0438] \u0432\u0435\u0437\u0434\u0435 <em>(sarvatra)</em> \u043D\u0430\u0445\u043E\u0434\u0438\u0442\u0441\u044F <em>(sa\u1E41sthita\u1E25)</em> \u0432 \u0432\u0438\u0434\u0435 <em>(bh\u0101vena)</em> \u0432\u043E\u0441\u043F\u0440\u0438\u043D\u0438\u043C\u0430\u0435\u043C\u043E\u0433\u043E <em>(bhogya)</em>.</p><ol><li>\u0414\u0440\u0443\u0433\u0438\u043C\u0438 \u0441\u043B\u043E\u0432\u0430\u043C\u0438, \u043F\u043E\u0442\u043E\u043C\u0443 \u0447\u0442\u043E \u0438\u043D\u0434\u0438\u0432\u0438\u0434\u0443\u0430\u043B\u044C\u043D\u0430 \u044F \u0434\u0443\u0448\u0430 \u0437\u043D\u0430\u0435\u0442 \u0432\u0441\u0435\u0445 \u0438\u0445.</li></ol></div><div class="stanza"><a href="#s2.5" id="s2.5" class="num">2.5</a><p class="sans">\u0907\u0924\u093F \u0935\u093E \u092F\u0938\u094D\u092F \u0938\u0902\u0935\u093F\u0924\u094D\u0924\u093F\u0903 \u0915\u094D\u0930\u0940\u0921\u093E\u0924\u094D\u0935\u0947\u0928\u093E\u0916\u093F\u0932\u0902 \u091C\u0917\u0924\u094D \u0964<br> \u0938 \u092A\u0936\u094D\u092F\u0928\u094D\u0938\u0924\u0924\u0902 \u092F\u0941\u0915\u094D\u0924\u094B \u091C\u0940\u0935\u0928\u094D\u092E\u0941\u0915\u094D\u0924\u094B \u0928 \u0938\u0902\u0936\u092F\u0903 \u0965\u096B\u0965</p><p class="trans">Iti v\u0101 yasya sa\u1E41vitti\u1E25 kr\u012B\u1E0D\u0101tven\u0101khila\u1E41 jagat\u0964<br> Sa pa\u015Byansatata\u1E41 yukto j\u012Bvanmukto na sa\u1E41\u015Baya\u1E25 \u09655\u0965</p><p>\u0418\u043B\u0438 \u0436\u0435 <em>(iti v\u0101)</em> \u0442\u043E\u0442 <em>(sa\u1E25)</em>, [\u043A\u0442\u043E \u043E\u0431\u043B\u0430\u0434\u0430\u0435\u0442] \u0442\u0435\u043C <em>(yasya)</em> \u043E\u0441\u043E\u0437\u043D\u0430\u043D\u0438\u0435\u043C <em>(sa\u1E41vitti)</em> [\u0438] \u043F\u043E\u0441\u0442\u043E\u044F\u043D\u043D\u043E <em>(satatam)</em> \u0441\u043E\u0435\u0434\u0438\u043D\u044F\u0435\u0442\u0441\u044F [\u0441 \u0412\u044B\u0441\u0448\u0438\u043C \u042F] <em>(yukta\u1E25)</em>, \u0432\u0438\u0434\u0438\u0442 <em>(pa\u015Byan)</em> \u0432\u0435\u0441\u044C <em>(akhilam)</em> \u043C\u0438\u0440 <em>(jagat)</em> \u043A\u0430\u043A [\u0431\u043E\u0436\u0435\u0441\u0442\u0432\u0435\u043D\u043D\u0443\u044E] \u0418\u0433\u0440\u0443 <em>(kr\u012B\u1E0D\u0101tvena)</em>. [\u0422\u0430\u043A\u0430\u044F \u043B\u0438\u0447\u043D\u043E\u0441\u0442\u044C], \u043D\u0435\u0441\u043E\u043C\u043D\u0435\u043D\u043D\u043E <em>(na sa\u1E41\u015Baya\u1E25)</em>, [\u044F\u0432\u043B\u044F\u0435\u0442\u0441\u044F] \u043E\u0441\u0432\u043E\u0431\u043E\u0436\u0434\u0451\u043D\u043D\u043E\u0439 \u043F\u0440\u0438 \u0436\u0438\u0437\u043D\u0438 <em>(j\u012Bvanmukta\u1E25)</em>.</p></div><div class="stanza"><a href="#s2.6" id="s2.6" class="num">2.6</a><p class="sans">\u0905\u092F\u092E\u0947\u0935\u094B\u0926\u092F\u0938\u094D\u0924\u0938\u094D\u092F \u0927\u094D\u092F\u0947\u092F\u0938\u094D\u092F \u0927\u094D\u092F\u093E\u092F\u093F\u091A\u0947\u0924\u0938\u093F \u0964<br> \u0924\u0926\u093E\u0924\u094D\u092E\u0924\u093E\u0938\u092E\u093E\u092A\u0924\u094D\u0924\u093F\u0930\u093F\u091A\u094D\u091B\u0924\u0903 \u0938\u093E\u0927\u0915\u0938\u094D\u092F \u092F\u093E \u0965\u096C\u0965</p><p class="trans">Ayamevodayastasya dhyeyasya dhy\u0101yicetasi\u0964<br> Tad\u0101tmat\u0101sam\u0101pattiricchata\u1E25 s\u0101dhakasya y\u0101 \u09656\u0965</p><p>\u0422\u043E\u043B\u044C\u043A\u043E <em>(eva)</em> \u044D\u0442\u043E <em>(ayam)</em> [\u043C\u043E\u0436\u043D\u043E \u043D\u0430\u0437\u0432\u0430\u0442\u044C] \u043F\u043E\u044F\u0432\u043B\u0435\u043D\u0438\u0435\u043C <em>(udaya\u1E25)</em> \u0442\u043E\u0433\u043E <em>(tasya)</em> \u043E\u0431\u044A\u0435\u043A\u0442\u0430 \u043C\u0435\u0434\u0438\u0442\u0430\u0446\u0438\u0438 <em>(dhyeya\u1E25)</em> \u0432 \u0443\u043C\u0435 <em>(cetasi)</em> \u043C\u0435\u0434\u0438\u0442\u0438\u0440\u0443\u044E\u0449\u0435\u0433\u043E <em>(dhy\u0101yi)</em>. \u0412 s\u0101dhaka --\u0434\u0443\u0445\u043E\u0432\u043D\u043E\u043C \u0438\u0441\u043A\u0430\u0442\u0435\u043B\u0435-- <em>(s\u0101dhakasya)</em> \u0441 \u0442\u0432\u0451\u0440\u0434\u043E\u0439 \u0432\u043E\u043B\u0435\u0439 <em>(icchata\u1E25)</em> \u043D\u0430\u0441\u0442\u0443\u043F\u0430\u0435\u0442 \u043E\u0441\u043E\u0437\u043D\u0430\u043D\u0438\u0435 <em>(sam\u0101patti\u1E25... y\u0101)</em> [\u0441\u0432\u043E\u0435\u0433\u043E] \u0442\u043E\u0436\u0434\u0435\u0441\u0442\u0432\u0430 [\u0442\u043E\u043C\u0443 dhyeya, \u043E\u0431\u044A\u0435\u043A\u0442\u0443 \u043C\u0435\u0434\u0438\u0442\u0430\u0446\u0438\u0438] <em>(tad\u0101tmat\u0101)</em>.</p></div><div class="stanza"><a href="#s2.7" id="s2.7" class="num">2.7</a><p class="sans">\u0907\u092F\u092E\u0947\u0935\u093E\u092E\u0943\u0924\u092A\u094D\u0930\u093E\u092A\u094D\u0924\u093F\u0930\u092F\u092E\u0947\u0935\u093E\u0924\u094D\u092E\u0928\u094B \u0917\u094D\u0930\u0939\u0903 \u0964<br> \u0907\u092F\u0902 \u0928\u093F\u0930\u094D\u0935\u093E\u0923\u0926\u0940\u0915\u094D\u0937\u093E \u091A \u0936\u093F\u0935\u0938\u0926\u094D\u092D\u093E\u0935\u0926\u093E\u092F\u093F\u0928\u0940 \u0965\u096D\u0965</p><p class="trans">Iyamev\u0101m\u1E5Btapr\u0101ptirayamev\u0101tmano graha\u1E25\u0964<br> Iya\u1E41 nirv\u0101\u1E47ad\u012Bk\u1E63\u0101 ca \u015Bivasadbh\u0101vad\u0101yin\u012B \u09657\u0965</p><p>\u0422\u043E\u043B\u044C\u043A\u043E <em>(eva)</em> \u044D\u0442\u043E <em>(iyam)</em> [\u044F\u0432\u043B\u044F\u0435\u0442\u0441\u044F] \u043F\u0440\u0438\u043E\u0431\u0440\u0435\u0442\u0435\u043D\u0438\u0435\u043C <em>(pr\u0101pti\u1E25)</em> \u041D\u0435\u043A\u0442\u0430\u0440\u0430 \u0411\u0435\u0441\u0441\u043C\u0435\u0440\u0442\u0438\u044F <em>(am\u1E5Bta)</em>, \u0442\u043E\u043B\u044C\u043A\u043E <em>(eva)</em> \u044D\u0442\u043E <em>(ayam)</em> [\u0435\u0441\u0442\u044C] \u0432\u043E\u0441\u043F\u0440\u0438\u044F\u0442\u0438\u0435 <em>(graha\u1E25)</em> \u0412\u044B\u0441\u0448\u0435\u0433\u043E \u042F <em>(\u0101tmana\u1E25)</em>. \u0418 <em>(ca)</em> \u044D\u0442\u0430 <em>(iyam)</em> \u0438\u043D\u0438\u0446\u0438\u0430\u0446\u0438\u044F <em>(d\u012Bk\u1E63\u0101)</em>, \u043F\u0440\u0438\u0432\u043E\u0434\u044F\u0449\u0430\u044F \u043A Nirv\u0101\u1E47a [\u041E\u043A\u043E\u043D\u0447\u0430\u0442\u0435\u043B\u044C\u043D\u043E\u043C\u0443 \u041E\u0441\u0432\u043E\u0431\u043E\u0436\u0434\u0435\u043D\u0438\u044E] <em>(nirv\u0101\u1E47a)</em> \u0434\u0430\u0440\u0443\u0435\u0442 <em>(d\u0101yin\u012B)</em> \u0438\u0441\u0442\u0438\u043D\u043D\u043E\u0435 <em>(sat)</em> \u0441\u043E\u0441\u0442\u043E\u044F\u043D\u0438\u0435 <em>(bh\u0101va)</em> \u0428\u0438\u0432\u044B <em>(\u015Biva)</em>.</p></div><h2 id="\u0447\u0430\u0441\u0442\u044C-iii-vibhutispanda" tabindex="-1">\u0427\u0430\u0441\u0442\u044C III: Vibh\u016Btispanda <a class="header-anchor" href="#\u0447\u0430\u0441\u0442\u044C-iii-vibhutispanda" aria-hidden="true">#</a></h2><p><strong>\u0421\u0432\u0435\u0440\u0445\u044A\u0435\u0441\u0442\u0435\u0441\u0442\u0432\u0435\u043D\u043D\u044B\u0435 \u0441\u0438\u043B\u044B \u043F\u0440\u043E\u0438\u0441\u0445\u043E\u0434\u044F\u0449\u0438\u0435 \u0438\u0437 \u0421\u043F\u0430\u043D\u0434\u044B</strong></p><div class="stanza"><a href="#s3.1-2" id="s3.1-2" class="num">3.1-2</a><p class="sans">\u092F\u0925\u0947\u091A\u094D\u091B\u093E\u092D\u094D\u092F\u0930\u094D\u0925\u093F\u0924\u094B \u0927\u093E\u0924\u093E \u091C\u093E\u0917\u094D\u0930\u0924\u094B\u093D\u0930\u094D\u0925\u093E\u0928\u094D \u0939\u0943\u0926\u093F \u0938\u094D\u0925\u093F\u0924\u093E\u0928\u094D \u0964<br> \u0938\u094B\u092E\u0938\u0942\u0930\u094D\u092F\u094B\u0926\u092F\u0902 \u0915\u0943\u0924\u094D\u0935\u093E \u0938\u092E\u094D\u092A\u093E\u0926\u092F\u0924\u093F \u0926\u0947\u0939\u093F\u0928\u0903 \u0965\u0967 \u0965</p><p class="sans">\u0924\u0925\u093E \u0938\u094D\u0935\u092A\u094D\u0928\u0947\u093D\u092A\u094D\u092F\u092D\u0940\u0937\u094D\u091F\u093E\u0930\u094D\u0925\u093E\u0928\u094D\u092A\u094D\u0930\u0923\u092F\u0938\u094D\u092F\u093E\u0928\u0924\u093F\u0915\u094D\u0930\u092E\u093E\u0924\u094D \u0964<br> \u0928\u093F\u0924\u094D\u092F\u0902 \u0938\u094D\u092B\u0941\u091F\u0924\u0930\u0902 \u092E\u0927\u094D\u092F\u0947 \u0938\u094D\u0925\u093F\u0924\u094B\u093D\u0935\u0936\u094D\u092F\u0902 \u092A\u094D\u0930\u0915\u093E\u0936\u092F\u0947\u0924\u094D \u0965\u0968\u0965</p><p class="trans">Yathecch\u0101bhyarthito dh\u0101t\u0101 j\u0101grato&#39;rth\u0101n h\u1E5Bdi sthit\u0101n\u0964<br> Somas\u016Bryodaya\u1E41 k\u1E5Btv\u0101 samp\u0101dayati dehina\u1E25 \u09651\u0965</p><p class="trans">Tath\u0101 svapne&#39;pyabh\u012B\u1E63\u1E6D\u0101rth\u0101npra\u1E47ayasy\u0101natikram\u0101t\u0964<br> Nitya\u1E41 sphu\u1E6Datara\u1E41 madhye sthito&#39;va\u015Bya\u1E41 prak\u0101\u015Bayet \u09652\u0965</p><p>\u041F\u043E\u0434\u043E\u0431\u043D\u043E \u0442\u043E\u043C\u0443 \u043A\u0430\u043A <em>(yath\u0101)</em> \u041F\u043E\u0434\u0434\u0435\u0440\u0436\u0438\u0432\u0430\u044E\u0449\u0438\u0439 [\u044D\u0442\u043E\u0442 \u043C\u0438\u0440] <em>(dh\u0101t\u0101)</em>, \u043A\u043E\u0433\u0434\u0430 \u0435\u0433\u043E \u043F\u0440\u043E\u0441\u044F\u0442 <em>(abhyarthita\u1E25)</em> \u0441 \u0436\u0435\u043B\u0430\u043D\u0438\u0435\u043C <em>(icch\u0101)</em>, \u0441\u043E\u0437\u0434\u0430\u0451\u0442 <em>(samp\u0101dayati)</em> [\u0432\u0441\u0435] \u043E\u0431\u044A\u0435\u043A\u0442\u044B <em>(arth\u0101n)</em>, \u043D\u0430\u0445\u043E\u0434\u044F\u0449\u0438\u0435\u0441\u044F <em>(sthit\u0101n)</em> \u0432 \u0441\u0435\u0440\u0434\u0446\u0435 <em>(h\u1E5Bdi)</em> \u0442\u043E\u0439 \u0432\u043E\u043F\u043B\u043E\u0449\u0451\u043D\u043D\u043E\u0439 \u0434\u0443\u0448\u0438 <em>(dehina\u1E25)</em>, \u043A\u043E\u0442\u043E\u0440\u0430\u044F \u0431\u043E\u0434\u0440\u0441\u0442\u0432\u0443\u0435\u0442 <em>(j\u0101grata\u1E25)</em>, \u0432\u044B\u0437\u0432\u0430\u0432 <em>(k\u1E5Btv\u0101)</em> \u043F\u043E\u044F\u0432\u043B\u0435\u043D\u0438\u0435 <em>(udayam)</em> \u043B\u0443\u043D\u044B <em>(soma)</em> [\u0438] \u0441\u043E\u043B\u043D\u0446\u0430 <em>(s\u016Brya)</em>, \u0442\u0430\u043A <em>(tath\u0101)</em> \u0438 <em>(api)</em> \u0432\u043E \u0441\u043D\u0435 <em>(svapne)</em>, \u043F\u0440\u0435\u0431\u044B\u0432\u0430\u044F*(sthitah)* \u0432 \u0446\u0435\u043D\u0442\u0440\u0430\u043B\u044C\u043D\u043E\u043C \u043A\u0430\u043D\u0430\u043B\u0435 <em>(madhye)</em>, [\u041E\u043D] \u043E\u043F\u0440\u0435\u0434\u0435\u043B\u0451\u043D\u043D\u043E <em>(ava\u015Byam)</em> \u0432\u0441\u0435\u0433\u0434\u0430 <em>(nityam)</em> \u044F\u0441\u043D\u043E <em>(sphu\u1E6Dataram)</em> \u043F\u0440\u043E\u044F\u0432\u043B\u044F\u0435\u0442 <em>(prak\u0101\u015Bayet)</em> \u0436\u0435\u043B\u0430\u0435\u043C\u044B\u0435 <em>(abh\u012B\u1E63\u1E6Da)</em> \u043E\u0431\u044A\u0435\u043A\u0442\u044B <em>(arth\u0101n)</em> \u0442\u043E\u043C\u0443, \u043A\u0442\u043E \u043D\u0435 \u043F\u0440\u0435\u043D\u0435\u0431\u0440\u0435\u0433\u0430\u0435\u0442 <em>(anatikram\u0101t)</em> \u0435\u0433\u043E \u043C\u043E\u043B\u044C\u0431\u043E\u0439 <em>(pra\u1E47ayasya)</em>.</p></div><div class="stanza"><a href="#s3.3" id="s3.3" class="num">3.3</a><p class="sans">\u0905\u0928\u094D\u092F\u0925\u093E \u0924\u0941 \u0938\u094D\u0935\u0924\u0928\u094D\u0924\u094D\u0930\u093E \u0938\u094D\u092F\u093E\u0924\u094D\u0938\u0943\u0937\u094D\u091F\u093F\u0938\u094D\u0924\u0926\u094D\u0927\u0930\u094D\u092E\u0915\u0924\u094D\u0935\u0924\u0903 \u0964<br> \u0938\u0924\u0924\u0902 \u0932\u094C\u0915\u093F\u0915\u0938\u094D\u092F\u0947\u0935 \u091C\u093E\u0917\u094D\u0930\u0924\u094D\u0938\u094D\u0935\u092A\u094D\u0928\u092A\u0926\u0926\u094D\u0935\u092F\u0947 \u0965\u0969\u0965</p><p class="trans">Anyath\u0101 tu svatantr\u0101 sy\u0101ts\u1E5B\u1E63\u1E6Distaddharmakatvata\u1E25\u0964<br> Satata\u1E41 laukikasyeva j\u0101gratsvapnapadadvaye \u09653\u0965</p><p>\u0418\u043D\u0430\u0447\u0435 <em>(anyath\u0101 tu)</em>, \u043F\u0440\u043E\u044F\u0432\u043B\u044F\u044E\u0449\u0430\u044F \u0441\u0438\u043B\u0430 <em>(s\u1E5B\u1E63\u1E6Di\u1E25)</em>, \u0441\u043E\u0433\u043B\u0430\u0441\u043D\u043E \u0435\u0451 <em>(tad)</em> \u043A\u0430\u0447\u0435\u0441\u0442\u0432\u0430\u043C <em>(dharmakatvata\u1E25)</em>, \u0432\u0441\u0435\u0433\u0434\u0430 <em>(satatam)</em> \u0441\u0432\u043E\u0431\u043E\u0434\u043D\u0430 <em>(sy\u0101t svatantr\u0101)</em> [\u0434\u0435\u0439\u0441\u0442\u0432\u043E\u0432\u0430\u0442\u044C], \u043A\u0430\u043A <em>(iva)</em> \u0432 \u0441\u043B\u0443\u0447\u0430\u0435 \u043E\u0431\u044B\u0447\u043D\u044B\u0445 \u043B\u044E\u0434\u0435\u0439 <em>(laukikasya)</em>, \u0432\u043E \u0432\u0440\u0435\u043C\u044F \u0434\u0432\u0443\u0445 <em>(dvaye)</em> \u0441\u043E\u0441\u0442\u043E\u044F\u043D\u0438\u0439 <em>(pada)</em> \u0431\u043E\u0434\u0440\u0441\u0442\u0432\u043E\u0432\u0430\u043D\u0438\u044F <em>(j\u0101grat)</em> [\u0438] \u0441\u043D\u0430 <em>(svapna)</em>.</p></div><div class="stanza"><a href="#s3.4-5" id="s3.4-5" class="num">3.4-5</a><p class="sans">\u092F\u0925\u093E \u0939\u094D\u092F\u0930\u094D\u0925\u094B\u093D\u0938\u094D\u092B\u0941\u091F\u094B \u0926\u0943\u0937\u094D\u091F\u0903 \u0938\u093E\u0935\u0927\u093E\u0928\u0947\u093D\u092A\u093F \u091A\u0947\u0924\u0938\u093F \u0964<br> \u092D\u0942\u092F\u0903 \u0938\u094D\u092B\u0941\u091F\u0924\u0930\u094B \u092D\u093E\u0924\u093F \u0938\u094D\u0935\u092C\u0932\u094B\u0926\u094D\u092F\u094B\u0917\u092D\u093E\u0935\u093F\u0924\u0903 \u0965\u096A \u0965</p><p class="sans">\u0924\u0925\u093E \u092F\u0924\u094D\u092A\u0930\u092E\u093E\u0930\u094D\u0925\u0947\u0928 \u092F\u0947\u0928 \u092F\u0924\u094D\u0930 \u092F\u0925\u093E \u0938\u094D\u0925\u093F\u0924\u092E\u094D \u0964<br> \u0924\u0924\u094D\u0924\u0925\u093E \u092C\u0932\u092E\u093E\u0915\u094D\u0930\u092E\u094D\u092F \u0928 \u091A\u093F\u0930\u093E\u0924\u094D\u0938\u092E\u094D\u092A\u094D\u0930\u0935\u0930\u094D\u0924\u0924\u0947 \u0965\u096B\u0965</p><p class="trans">Yath\u0101 hyartho&#39;sphu\u1E6Do d\u1E5B\u1E63\u1E6Da\u1E25 s\u0101vadh\u0101ne&#39;pi cetasi\u0964<br> Bh\u016Bya\u1E25 sphu\u1E6Dataro bh\u0101ti svabalodyogabh\u0101vita\u1E25 \u09654\u0965</p><p class="trans">Tath\u0101 yatparam\u0101rthena yena yatra yath\u0101 sthitam\u0964<br> Tattath\u0101 balam\u0101kramya na cir\u0101tsampravartate \u09655\u0965</p><p>\u041D\u0435\u0441\u043E\u043C\u043D\u0435\u043D\u043D\u043E <em>(hi)</em>, \u043F\u043E\u0434\u043E\u0431\u043D\u043E \u0442\u043E\u043C\u0443 \u043A\u0430\u043A <em>(yath\u0101)</em> \u043F\u0440\u0435\u0434\u043C\u0435\u0442 <em>(artha\u1E25)</em> [\u0441\u043D\u0430\u0447\u0430\u043B\u0430] \u0432\u043E\u0441\u043F\u0440\u0438\u043D\u0438\u043C\u0430\u0442\u0435\u0441\u044F <em>(d\u1E5B\u1E63\u1E6Da\u1E25)</em> \u043D\u0435\u0447\u0451\u0442\u043A\u043E <em>(asphu\u1E6Dam)</em>, \u0434\u0430\u0436\u0435 <em>(api)</em> [\u043A\u0440\u0430\u0439\u043D\u0435] \u0432\u043D\u0438\u043C\u0430\u0442\u0435\u043B\u044C\u043D\u044B\u043C <em>(sa-avadh\u0101ne)</em> \u0443\u043C\u043E\u043C <em>(cetasi)</em>, [\u0438] \u043A\u0430\u0436\u0435\u0442\u0441\u044F <em>(bh\u0101ti)</em> \u0431\u043E\u043B\u0435\u0435 \u0447\u0451\u0442\u043A\u0438\u043C <em>(sphu\u1E6Datara\u1E25)</em> \u043F\u043E\u0437\u0436\u0435 <em>(bh\u016Byas)</em>, \u043F\u0440\u0438 \u0440\u0430\u0441\u0441\u043C\u043E\u0442\u0440\u0435\u043D\u0438\u0438 <em>(bh\u0101vita\u1E25)</em> \u0437\u0430 \u0441\u0447\u0451\u0442 \u0430\u043A\u0442\u0438\u0432\u043D\u043E\u0433\u043E \u043F\u0440\u0438\u043C\u0435\u043D\u0435\u043D\u0438\u044F <em>(udyoga)</em> \u0441\u043E\u0431\u0441\u0442\u0432\u0435\u043D\u043D\u043E\u0439 <em>(sva)</em> \u0441\u0438\u043B\u044B <em>(bala)</em><sup>1</sup>, \u0442\u0430\u043A \u0436\u0435 <em>(tath\u0101)</em>, \u0443\u0445\u0432\u0430\u0442\u044B\u0432\u0430\u044F\u0441\u044C <em>(\u0101kramya)</em> \u0437\u0430 [\u041A\u043E\u0441\u043C\u0438\u0447\u0435\u0441\u043A\u0443\u044E] \u0421\u0438\u043B\u0443 <em>(balam)</em>, \u043B\u044E\u0431\u043E\u0439 \u043E\u0431\u044A\u0435\u043A\u0442 <em>(yad)</em>, \u0434\u0435\u0439\u0441\u0442\u0432\u0438\u0442\u0435\u043B\u044C\u043D\u043E <em>(param\u0101rthena)</em> \u0441\u0443\u0449\u0435\u0441\u0442\u0432\u0443\u044E\u0449\u0438\u0439 <em>(sthitam)</em> \u0432 \u043B\u044E\u0431\u043E\u0439 \u0444\u043E\u0440\u043C\u0435 <em>(yena)</em>, \u0433\u0434\u0435 \u0443\u0433\u043E\u0434\u043D\u043E <em>(yatra)</em>, [\u0438] \u043F\u0440\u0438 \u043B\u044E\u0431\u044B\u0445 \u0443\u0441\u043B\u043E\u0432\u0438\u044F\u0445 <em>(yath\u0101)</em>, \u044D\u0442\u043E\u0442 [\u0441\u0430\u043C\u044B\u0439 \u043E\u0431\u044A\u0435\u043A\u0442] <em>(tad)</em> \u043D\u0435\u043C\u0435\u0434\u043B\u0435\u043D\u043D\u043E <em>(na cir\u0101t)</em> \u043F\u0440\u043E\u044F\u0432\u043B\u044F\u0435\u0442\u0441\u044F <em>(sampravartate)</em> \u0442\u0430\u043A\u0438\u043C \u0436\u0435 \u043E\u0431\u0440\u0430\u0437\u043E\u043C <em>(tath\u0101)</em>.</p><ol><li>\u0417\u0434\u0435\u0441\u044C \u043F\u043E\u0434\u0440\u0430\u0437\u0443\u043C\u0435\u0432\u0430\u0435\u0442\u0441\u044F Cak\u1E63urindriya, \u0441\u0438\u043B\u0430 \u0437\u0440\u0435\u043D\u0438\u044F. \u041E\u043D\u0430 \u044F\u0432\u043B\u044F\u0435\u0442\u0441\u044F \u043F\u0440\u0438\u0447\u0438\u043D\u043E\u0439 \u0437\u0440\u0435\u043D\u0438\u044F, \u0431\u0443\u0434\u0443\u0447\u0438 \u043D\u0435 \u0444\u0438\u0437\u0438\u0447\u0435\u0441\u043A\u0438\u043C \u043E\u0440\u0433\u0430\u043D\u043E\u043C, \u0430 \u044D\u043D\u0435\u0440\u0433\u0438\u0435\u0439, \u0446\u0438\u0440\u043A\u0443\u043B\u0438\u0440\u0443\u044E\u0449\u0435\u0439 \u0432 \u043D\u0451\u043C.</li></ol></div><div class="stanza"><a href="#s3.6" id="s3.6" class="num">3.6</a><p class="sans">\u0926\u0941\u0930\u094D\u092C\u0932\u094B\u093D\u092A\u093F \u0924\u0926\u093E\u0915\u094D\u0930\u092E\u094D\u092F \u092F\u0924\u0903 \u0915\u093E\u0930\u094D\u092F\u0947 \u092A\u094D\u0930\u0935\u0930\u094D\u0924\u0924\u0947 \u0964<br> \u0906\u091A\u094D\u091B\u093E\u0926\u092F\u0947\u0926\u094D\u092C\u0941\u092D\u0941\u0915\u094D\u0937\u093E\u0902 \u091A \u0924\u0925\u093E \u092F\u094B\u093D\u0924\u093F\u092C\u0941\u092D\u0941\u0915\u094D\u0937\u093F\u0924\u0903 \u0965\u096C\u0965</p><p class="trans">Durbalo&#39;pi tad\u0101kramya yata\u1E25 k\u0101rye pravartate\u0964<br> \u0100cch\u0101dayedbubhuk\u1E63\u0101\u1E41 ca tath\u0101 yo&#39;tibubhuk\u1E63ita\u1E25 \u09656\u0965</p><p>\u0414\u0430\u0436\u0435 <em>(api)</em> \u0441\u043B\u0430\u0431\u043E\u0435 \u0441\u0443\u0449\u0435\u0441\u0442\u0432\u043E <em>(durbala\u1E25)</em>, \u0443\u0445\u0432\u0430\u0442\u044B\u0432\u0430\u044F\u0441\u044C <em>(\u0101kramya)</em> \u0437\u0430 \u0442\u043E [\u0421\u043F\u0430\u043D\u0434\u0443] <em>(tad)</em>, \u0437\u0430\u043D\u0438\u043C\u0430\u0435\u0442\u0441\u044F <em>(pravartate)</em> \u0442\u0435\u043C, \u0447\u0442\u043E \u043D\u0443\u0436\u043D\u043E \u0441\u0434\u0435\u043B\u0430\u0442\u044C <em>(k\u0101rye)</em> [\u0438 \u043F\u0440\u0435\u0443\u0441\u043F\u0435\u0432\u0430\u0435\u0442] \u0437\u0430 \u0441\u0447\u0451\u0442 \u044D\u0442\u043E\u0433\u043E \u0441\u0430\u043C\u043E\u0433\u043E \u041F\u0440\u0438\u043D\u0446\u0438\u043F\u0430 <em>(yatas)</em>. \u041F\u043E\u0434\u043E\u0431\u043D\u044B\u043C \u043E\u0431\u0440\u0430\u0437\u043E\u043C, <em>(ca tath\u0101)</em> \u0442\u043E\u0442, \u043A\u0442\u043E <em>(ya\u1E25)</em> \u043A\u0440\u0430\u0439\u043D\u0435 \u0433\u043E\u043B\u043E\u0434\u0435\u043D <em>(ati-bubhuk\u1E63ita\u1E25)</em>, \u0441\u043A\u0440\u044B\u0432\u0430\u0435\u0442 <em>(\u0101ch\u0101dayet)</em><sup>1</sup> [\u0441\u0432\u043E\u0435] \u0436\u0435\u043B\u0430\u043D\u0438\u0435 \u043F\u043E\u0435\u0441\u0442\u044C <em>(bubhuk\u1E63\u0101m)</em>.</p><ol><li>\u0418\u043C\u0435\u0435\u0442\u0441\u044F \u0432 \u0432\u0438\u0434\u0443 \xAB\u043F\u0440\u0435\u043E\u0434\u043E\u043B\u0435\u0432\u0430\u0435\u0442\xBB.</li></ol></div><div class="stanza"><a href="#s3.7" id="s3.7" class="num">3.7</a><p class="sans">\u0905\u0928\u0947\u0928\u093E\u0927\u093F\u0937\u094D\u0920\u093F\u0924\u0947 \u0926\u0947\u0939\u0947 \u092F\u0925\u093E \u0938\u0930\u094D\u0935\u091C\u094D\u091E\u0924\u093E\u0926\u092F\u0903 \u0964<br> \u0924\u0925\u093E \u0938\u094D\u0935\u093E\u0924\u094D\u092E\u0928\u094D\u092F\u0927\u093F\u0937\u094D\u0920\u093E\u0928\u093E\u0924\u094D\u0938\u0930\u094D\u0935\u0924\u094D\u0930\u0948\u0935\u0902 \u092D\u0935\u093F\u0937\u094D\u092F\u0924\u093F \u0965\u096D\u0965</p><p class="trans">Anen\u0101dhi\u1E63\u1E6Dhite dehe yath\u0101 sarvaj\xF1at\u0101daya\u1E25\u0964<br> Tath\u0101 sv\u0101tmanyadhi\u1E63\u1E6Dh\u0101n\u0101tsarvatraiva\u1E41 bhavi\u1E63yati \u09657\u0965</p><p>\u041F\u043E\u0434\u043E\u0431\u043D\u043E \u0442\u043E\u043C\u0443 \u043A\u0430\u043A <em>(yath\u0101)</em> [\u0441\u0443\u0449\u0435\u0441\u0442\u0432\u0443\u0435\u0442] \u0432\u0441\u0435\u0437\u043D\u0430\u043D\u0438\u0435 <em>(sarvaj\xF1at\u0101)</em> \u0438 \u0442.\u0434. <em>(\u0101daya\u1E25)</em> \u043E\u0442\u043D\u043E\u0441\u0438\u0442\u0435\u043B\u044C\u043D\u043E \u0442\u0435\u043B\u0430 <em>(dehe)</em>, \u0443\u043F\u0440\u0430\u0432\u043B\u044F\u0435\u043C\u043E\u0433\u043E <em>(adhi\u1E63\u1E6Dhite)</em> \u044D\u0442\u0438\u043C [\u041F\u0440\u0438\u043D\u0446\u0438\u043F\u043E\u043C \u0421\u043F\u0430\u043D\u0434\u044B] <em>(anena)</em>, \u0442\u0430\u043A \u0436\u0435 \u0438 <em>(tath\u0101)</em>, \u0435\u0441\u043B\u0438 \u0443\u043A\u043E\u0440\u0435\u043D\u0438\u0442\u044C\u0441\u044F <em>(adhi\u1E63\u1E6Dh\u0101n\u0101t)</em> \u0432 \u0441\u043E\u0431\u0441\u0442\u0432\u0435\u043D\u043D\u043E\u043C <em>(sva)</em> \u0412\u044B\u0441\u0448\u0435\u043C \u042F <em>(\u0101tmani)</em>, \u043E\u043D\u043E \u0431\u0443\u0434\u0435\u0442 [\u043F\u0440\u0438\u0441\u0443\u0442\u0441\u0442\u0432\u043E\u0432\u0430\u0442\u044C] <em>(bhavi\u1E63yati)</em> \u044D\u0442\u0438\u043C \u043E\u0431\u0440\u0430\u0437\u043E\u043C <em>(evam)</em> \u0432\u0435\u0437\u0434\u0435 <em>(sarvatra)</em>.</p></div><div class="stanza"><a href="#s3.18" id="s3.18" class="num">3.18</a><p class="sans">\u0917\u094D\u0932\u093E\u0928\u093F\u0930\u094D\u0935\u093F\u0932\u0941\u0923\u094D\u0920\u093F\u0915\u093E \u0926\u0947\u0939\u0947 \u0924\u0938\u094D\u092F\u093E\u0936\u094D\u091A\u093E\u091C\u094D\u091E\u093E\u0928\u0924\u0903 \u0938\u0943\u0924\u093F\u0903 \u0964<br> \u0924\u0926\u0941\u0928\u094D\u092E\u0947\u0937\u0935\u093F\u0932\u0941\u092A\u094D\u0924\u0902 \u091A\u0947\u0924\u094D\u0915\u0941\u0924\u0903 \u0938\u093E \u0938\u094D\u092F\u093E\u0926\u0939\u0947\u0924\u0941\u0915\u093E \u0965\u096E\u0965</p><p class="trans">Gl\u0101nirvilu\u1E47\u1E6Dhik\u0101 dehe tasy\u0101\u015Bc\u0101j\xF1\u0101nata\u1E25 s\u1E5Bti\u1E25\u0964<br> Tadunme\u1E63avilupta\u1E41 cetkuta\u1E25 s\u0101 sy\u0101dahetuk\u0101 \u09658\u0965</p><p>\u0414\u0435\u043F\u0440\u0435\u0441\u0441\u0438\u044F <em>(gl\u0101ni\u1E25)</em> [\u043F\u043E\u0434\u043E\u0431\u043D\u0430] \u0432\u043E\u0440\u0443 <em>(vilu\u1E47\u1E6Dhik\u0101)</em> \u0432 \u0442\u0435\u043B\u0435 <em>(dehe)</em>. \u041E\u043D\u0430 \u043F\u0440\u043E\u0438\u0441\u0442\u0435\u043A\u0430\u0435\u0442 <em>(tasy\u0101\u1E25 ca... s\u1E5Bti\u1E25)</em><sup>1</sup> \u0438\u0437 \u043D\u0435\u0432\u0435\u0436\u0435\u0441\u0442\u0432\u0430 <em>(aj\xF1\u0101nata\u1E25)</em>. \u0415\u0441\u043B\u0438 <em>(ced)</em> \u043E\u043D\u043E \u0440\u0430\u0437\u0440\u0443\u0448\u0430\u0435\u0442\u0441\u044F <em>(viluptam)</em> \u0442\u0435\u043C <em>(tad)</em> Unme\u1E63a --\u0441\u043C. \u0441\u043B\u0435\u0434. \u0430\u0444\u043E\u0440\u0438\u0437\u043C-- <em>(unme\u1E63a)</em>, \u043A\u0430\u043A <em>(kutas)</em> \u043C\u043E\u0436\u0435\u0442 \u0442\u0430 [\u0434\u0435\u043F\u0440\u0435\u0441\u0441\u0438\u044F] \u0441\u0443\u0449\u0435\u0441\u0442\u0432\u043E\u0432\u0430\u0442\u044C <em>(s\u0101 sy\u0101t)</em> \u0431\u0435\u0437 [\u0441\u0432\u043E\u0435\u0439] \u043F\u0440\u0438\u0447\u0438\u043D\u044B <em>(ahetuk\u0101)</em>?</p><ol><li>\u0414\u043E\u0441\u043B. \xAB\u0441\u043A\u043E\u043B\u044C\u0436\u0435\u043D\u0438\u0435 \u0442\u043E\u0433\u043E\xBB, \u0441\u043A\u043E\u043B\u044C\u0436\u0435\u043D\u0438\u0435 gl\u0101ni, \u0434\u0435\u043F\u0440\u0435\u0441\u0441\u0438\u0438.</li></ol></div><div class="stanza"><a href="#s3.9" id="s3.9" class="num">3.9</a><p class="sans">\u090F\u0915\u091A\u093F\u0928\u094D\u0924\u093E\u092A\u094D\u0930\u0938\u0915\u094D\u0924\u0938\u094D\u092F \u092F\u0924\u0903 \u0938\u094D\u092F\u093E\u0926\u092A\u0930\u094B\u0926\u092F\u0903 \u0964<br> \u0909\u0928\u094D\u092E\u0947\u0937\u0903 \u0938 \u0924\u0941 \u0935\u093F\u091C\u094D\u091E\u0947\u092F\u0903 \u0938\u094D\u0935\u092F\u0902 \u0924\u092E\u0941\u092A\u0932\u0915\u094D\u0937\u092F\u0947\u0924\u094D \u0965\u096F\u0965</p><p class="trans">Ekacint\u0101prasaktasya yata\u1E25 sy\u0101daparodaya\u1E25\u0964<br> Unme\u1E63a\u1E25 sa tu vij\xF1eya\u1E25 svaya\u1E41 tamupalak\u1E63ayet \u09659\u0965</p><p>\u0422\u043E <em>(sa\u1E25)</em> \u043E\u043F\u0440\u0435\u0434\u0435\u043B\u0451\u043D\u043D\u043E \u0434\u043E\u043B\u0436\u043D\u043E \u0431\u044B\u0442\u044C \u043F\u043E\u0437\u043D\u0430\u043D\u043E \u043A\u0430\u043A <em>(tu vij\xF1eya\u1E25)</em> Unme\u1E63a <em>(unme\u1E63a\u1E25)</em>, \u043E\u0442\u043A\u0443\u0434\u0430 <em>(yatas)</em> \u043F\u0440\u043E\u0438\u0441\u0445\u043E\u0434\u0438\u0442 <em>(sy\u0101t)</em> \u043F\u043E\u044F\u0432\u043B\u0435\u043D\u0438\u0435 <em>(udaya\u1E25)</em> \u0434\u0440\u0443\u0433\u043E\u0433\u043E [\u043E\u0441\u043E\u0437\u043D\u0430\u043D\u0438\u044F --\u0441\u043E\u0433\u043B\u0430\u0441\u043D\u043E K\u1E63emar\u0101ja-- \u0438\u043B\u0438 \u043C\u044B\u0441\u043B\u0438 --\u0441\u043E\u0433\u043B\u0430\u0441\u043D\u043E \u0434\u0440. \u0430\u0432\u0442\u043E\u0440\u0430\u043C--] <em>(apara)</em> \u0432 [\u043B\u0438\u0447\u043D\u043E\u0441\u0442\u0438], \u043A\u043E\u0442\u043E\u0440\u0430\u044F [\u0443\u0436\u0435] \u0437\u0430\u043D\u044F\u0442\u0430 <em>(prasaktasya)</em> \u043E\u0434\u043D\u043E\u0439 <em>(eka)</em> \u043C\u044B\u0441\u043B\u044C\u044E <em>(cint\u0101)</em>. \u0421\u043B\u0435\u0434\u0443\u0435\u0442 \u0432\u043E\u0441\u043F\u0440\u0438\u043D\u0438\u043C\u0430\u0442\u044C <em>(upalak\u1E63ayet)</em> \u0442\u043E [Unme\u1E63a] <em>(tam)</em> \u0441\u0430\u043C\u043E\u0441\u0442\u043E\u044F\u0442\u0435\u043B\u044C\u043D\u043E <em>(svayam)</em>.</p></div><div class="stanza"><a href="#s3.10" id="s3.10" class="num">3.10</a><p class="sans">\u0905\u0924\u094B \u0935\u093F\u0928\u094D\u0926\u0941\u0930\u0924\u094B \u0928\u093E\u0926\u094B \u0930\u0942\u092A\u092E\u0938\u094D\u092E\u093E\u0926\u0924\u094B \u0930\u0938\u0903 \u0964<br> \u092A\u094D\u0930\u0935\u0930\u094D\u0924\u0928\u094D\u0924\u0947\u093D\u091A\u093F\u0930\u0947\u0923\u0948\u0935 \u0915\u094D\u0937\u094B\u092D\u0915\u0924\u094D\u0935\u0947\u0928 \u0926\u0947\u0939\u093F\u0928\u0903 \u0965\u0967\u0966\u0965</p><p class="trans">Ato vindurato n\u0101do r\u016Bpamasm\u0101dato rasa\u1E25\u0964<br> Pravartante&#39;cire\u1E47aiva k\u1E63obhakatvena dehina\u1E25 \u096510\u0965</p><p>\u0418\u0437 \u044D\u0442\u043E\u0433\u043E [Unme\u1E63a] <em>(atas... atas... asm\u0101t atas)</em> \u0432\u0441\u043A\u043E\u0440\u0435 <em>(acire\u1E47a eva)</em> \u043F\u043E\u044F\u0432\u043B\u044F\u044E\u0442\u0441\u044F <em>(pravartante)</em> \u0412\u0438\u043D\u0434\u0443 --\u0431\u043E\u0436\u0435\u0441\u0442\u0432\u0435\u043D\u043D\u044B\u0439 \u0441\u0432\u0435\u0442--<em>(vindu\u1E25)</em><sup>1</sup>, \u041D\u0430\u0434\u0430 --\u0431\u043E\u0436\u0435\u0441\u0442\u0432\u0435\u043D\u043D\u044B\u0439 \u0437\u0432\u0443\u043A-- <em>(n\u0101da\u1E25)</em>, \u0420\u0443\u043F\u0430 --\u0431\u043E\u0436\u0435\u0441\u0442\u0432\u0435\u043D\u043D\u0430\u044F \u0444\u043E\u0440\u043C\u0430-- <em>(r\u016Bpam)</em> [\u0438] \u0420\u0430\u0441\u0430 --\u0431\u043E\u0436\u0435\u0441\u0442\u0432\u0435\u043D\u043D\u044B\u0439 \u0432\u043A\u0443\u0441-- <em>(rasa\u1E25)</em> \u043A\u0430\u043A \u0444\u0430\u043A\u0442\u043E\u0440\u044B, \u043D\u0430\u0440\u0443\u0448\u0430\u044E\u0449\u0438\u0435 \u043F\u043E\u043A\u043E\u0439 <em>(k\u1E63obhakatvena)</em> \u0432\u043E\u043F\u043B\u043E\u0449\u0451\u043D\u043D\u043E\u0439 \u0434\u0443\u0448\u0438 <em>(dehina\u1E25)</em>.</p><ol><li>\u0418\u043B\u0438 \xAB\u0411\u0438\u043D\u0434\u0443\xBB \u0432 \u0434\u0440\u0443\u0433\u043E\u043C \u043D\u0430\u043F\u0438\u0441\u0430\u043D\u0438\u0438.</li></ol></div><div class="stanza"><a href="#s3.11" id="s3.11" class="num">3.11</a><p class="sans">\u0926\u093F\u0926\u0943\u0915\u094D\u0937\u092F\u0947\u0935 \u0938\u0930\u094D\u0935\u093E\u0930\u094D\u0925\u093E\u0928\u094D\u092F\u0926\u093E \u0935\u094D\u092F\u093E\u092A\u094D\u092F\u093E\u0935\u0924\u093F\u0937\u094D\u0920\u0924\u0947 \u0964<br> \u0924\u0926\u093E \u0915\u093F\u0902 \u092C\u0939\u0941\u0928\u094B\u0915\u094D\u0924\u0947\u0928 \u0938\u094D\u0935\u092F\u092E\u0947\u0935\u093E\u0935\u092D\u094B\u0924\u094D\u0938\u094D\u092F\u0924\u0947 \u0965\u0967\u0967 \u0965</p><p class="trans">Did\u1E5Bk\u1E63ayeva sarv\u0101rth\u0101nyad\u0101 vy\u0101py\u0101vati\u1E63\u1E6Dhate\u0964<br> Tad\u0101 ki\u1E41 bahunoktena svayamev\u0101vabhotsyate \u096511\u0965</p><p>\u041A\u043E\u0433\u0434\u0430 <em>(yad\u0101)</em> [\u0419\u043E\u0433,] \u0436\u0435\u043B\u0430\u044E\u0449\u0438\u0439 \u0443\u0432\u0438\u0434\u0435\u0442\u044C <em>(did\u1E5Bk\u1E63ay\u0101)</em>, \u0443\u0441\u043B\u043E\u0432\u043D\u043E \u0433\u043E\u0432\u043E\u0440\u044F <em>(iva)</em>, \u0432\u0441\u0435 <em>(sarva)</em> \u043E\u0431\u044A\u0435\u043A\u0442\u044B <em>(arth\u0101n)</em>, \u043F\u0440\u0435\u0431\u044B\u0432\u0430\u0435\u0442 [\u0432 \u0441\u043E\u0441\u0442\u043E\u044F\u043D\u0438\u0438] <em>(avati\u1E63\u1E6Dhate)</em> \u043F\u0440\u043E\u043D\u0438\u043A\u043D\u043E\u0432\u0435\u043D\u0438\u044F <em>(vy\u0101pya)</em> [\u0432\u043E \u0432\u0441\u0435\u0445 \u043D\u0438\u0445], \u0442\u043E\u0433\u0434\u0430 <em>(tad\u0101)</em>, \u043A\u0430\u043A\u043E\u0439 [\u0441\u043C\u044B\u0441\u043B] <em>(kim)</em> \u043C\u043D\u043E\u0433\u043E <em>(bahun\u0101)</em> \u0433\u043E\u0432\u043E\u0440\u0438\u0442\u044C <em>(uktena)</em> [\u043E\u0431 \u044D\u0442\u043E\u043C]? \u041E\u043D \u0438\u0441\u043F\u044B\u0442\u0430\u0435\u0442 [\u044D\u0442\u043E] <em>(avabhotsyate)</em> \u0441\u0430\u043C <em>(svayam eva)</em>!</p></div><div class="stanza"><a href="#s3.12" id="s3.12" class="num">3.12</a><p class="sans">\u092A\u094D\u0930\u092C\u0941\u0926\u094D\u0927\u0903 \u0938\u0930\u094D\u0935\u0926\u093E \u0924\u093F\u0937\u094D\u0920\u0947\u091C\u094D\u091C\u094D\u091E\u093E\u0928\u0947\u0928\u093E\u0932\u094B\u0915\u094D\u092F \u0917\u094B\u091A\u0930\u092E\u094D \u0964<br> \u090F\u0915\u0924\u094D\u0930\u093E\u0930\u094B\u092A\u092F\u0947\u0924\u094D\u0938\u0930\u094D\u0935\u0902 \u0924\u0924\u094B\u093D\u0928\u094D\u092F\u0947\u0928 \u0928 \u092A\u0940\u0921\u094D\u092F\u0924\u0947 \u0965\u0967\u0968\u0965</p><p class="trans">Prabuddha\u1E25 sarvad\u0101 ti\u1E63\u1E6Dhejj\xF1\u0101nen\u0101lokya gocaram\u0964<br> Ekatr\u0101ropayetsarva\u1E41 tato&#39;nyena na p\u012B\u1E0Dyate \u096512\u0965</p><p>\u0421\u043E\u0437\u0435\u0440\u0446\u0430\u044F <em>(\u0101lokya)</em> \u0432\u0441\u0451 \u0434\u043E\u0441\u0442\u0443\u043F\u043D\u043E\u0435 \u0441\u0432\u043E\u0435\u043C\u0443 \u0432\u043E\u0441\u043F\u0440\u0438\u044F\u0442\u0438\u044E <em>(gocaram)</em> \u0441 \u043F\u043E\u043C\u043E\u0449\u044C\u044E \u0437\u043D\u0430\u043D\u0438\u044F <em>(j\xF1\u0101nena)</em>, \u0441\u043B\u0435\u0434\u0443\u0435\u0442 \u0432\u0441\u0435\u0433\u0434\u0430 \u043E\u0441\u0442\u0430\u0432\u0430\u0442\u044C\u0441\u044F <em>(sarvad\u0101 ti\u1E63\u1E6Dhet)</em> \u0431\u043E\u0434\u0440\u0441\u0442\u0432\u0443\u044E\u0449\u0438\u043C <em>(prabuddha\u1E25)</em> [\u0438] \u0432\u043A\u043B\u0430\u0434\u044B\u0432\u0430\u0442\u044C <em>(\u0101ropayet)</em> \u0432\u0441\u0451 <em>(sarvam)</em> \u0432 \u043E\u0434\u043D\u0443 \u0442\u043E\u0447\u043A\u0443 <em>(ekatra)</em> --\u0432 \u0421\u043F\u0430\u043D\u0434\u0443--. \u0421\u043B\u0435\u0434\u043E\u0432\u0430\u0442\u0435\u043B\u044C\u043D\u043E <em>(tatas)</em>, [\u0442\u0430\u043A\u0430\u044F \u043B\u0438\u0447\u043D\u043E\u0441\u0442\u044C] \u043D\u0435 <em>(na)</em> \u043E\u0431\u0435\u0441\u043F\u043E\u043A\u043E\u0435\u043D\u0430 <em>(p\u012B\u1E0Dyate)</em> \u0434\u0440\u0443\u0433\u0438\u043C <em>(anyena)</em>.</p></div><div class="stanza"><a href="#s3.13" id="s3.13" class="num">3.13</a><p class="sans">\u0936\u092C\u094D\u0926\u0930\u093E\u0936\u093F\u0938\u092E\u0941\u0924\u094D\u0925\u0938\u094D\u092F \u0936\u0915\u094D\u0924\u093F\u0935\u0930\u094D\u0917\u0938\u094D\u092F \u092D\u094B\u0917\u094D\u092F\u0924\u093E\u092E\u094D \u0964<br> \u0915\u0932\u093E\u0935\u093F\u0932\u0941\u092A\u094D\u0924\u0935\u093F\u092D\u0935\u094B \u0917\u0924\u0903 \u0938\u0928\u094D\u0938 \u092A\u0936\u0941\u0903 \u0938\u094D\u092E\u0943\u0924\u0903 \u0965\u0967\u0969\u0965</p><p class="trans">\u015Aabdar\u0101\u015Bisamutthasya \u015Baktivargasya bhogyat\u0101m\u0964<br> Kal\u0101viluptavibhavo gata\u1E25 sansa pa\u015Bu\u1E25 sm\u1E5Bta\u1E25 \u096513\u0965</p><p>\u0422\u043E\u0442, \u043A\u043E\u0433\u043E Kal\u0101 <em>(kal\u0101)</em> \u043B\u0438\u0448\u0438\u043B\u0430 <em>(vilupta)</em> \u0435\u0433\u043E \u0432\u0435\u043B\u0438\u0447\u0438\u044F <em>(vibhava\u1E25)</em>, \u044F\u0432\u043B\u044F\u0435\u0442\u0441\u044F \u043E\u0431\u044A\u0435\u043A\u0442\u043E\u043C \u043D\u0430\u0441\u043B\u0430\u0436\u0434\u0435\u043D\u0438\u044F --\u0441\u0442\u0430\u043D\u043E\u0432\u0438\u0442\u0441\u044F \u0436\u0435\u0440\u0442\u0432\u043E\u0439-- <em>(gata\u1E25 san... bhogyat\u0101m)</em> \u0433\u0440\u0443\u043F\u043F\u044B <em>(vargasya)</em> \u0441\u0438\u043B <em>(\u015Bakti)</em>, \u043F\u0440\u043E\u0438\u0441\u0445\u043E\u0434\u044F\u0449\u0438\u0445 <em>(samutthasya)</em> \u0438\u0437 \u043C\u043D\u043E\u0436\u0435\u0441\u0442\u0432\u0430 <em>(r\u0101\u015Bi)</em> \u0441\u043B\u043E\u0432 <em>(\u015Babda)</em>. [\u041F\u043E\u044D\u0442\u043E\u043C\u0443,] \u043E\u043D <em>(sa\u1E25)</em> \u0438\u0437\u0432\u0435\u0441\u0442\u0435\u043D <em>(sm\u1E5Bta\u1E25)</em> \u043A\u0430\u043A pa\u015Bu --\u043E\u0433\u0440\u0430\u043D\u0438\u0447\u0435\u043D\u043D\u043E\u0435 \u0441\u0443\u0449\u0435\u0441\u0442\u0432\u043E-- <em>(pa\u015Bu\u1E25)</em>.</p></div><div class="stanza"><a href="#s3.14" id="s3.14" class="num">3.14</a><p class="sans">\u092A\u0930\u093E\u092E\u0943\u0924\u0930\u0938\u093E\u092A\u093E\u092F\u0938\u094D\u0924\u0938\u094D\u092F \u092F\u0903 \u092A\u094D\u0930\u0924\u094D\u092F\u092F\u094B\u0926\u094D\u092D\u0935\u0903 \u0964<br> \u0924\u0947\u0928\u093E\u0938\u094D\u0935\u0924\u0928\u094D\u0924\u094D\u0930\u0924\u093E\u092E\u0947\u0924\u093F \u0938 \u091A \u0924\u0928\u094D\u092E\u093E\u0924\u094D\u0930\u0917\u094B\u091A\u0930\u0903 \u0965\u0967\u096A\u0965</p><p class="trans">Par\u0101m\u1E5Btaras\u0101p\u0101yastasya ya\u1E25 pratyayodbhava\u1E25\u0964<br> Ten\u0101svatantrat\u0101meti sa ca tanm\u0101tragocara\u1E25 \u096514\u0965</p><p>\u0412\u043E\u0437\u043D\u0438\u043A\u043D\u043E\u0432\u0435\u043D\u0438\u0435 <em>(udbhava\u1E25)</em> \u0438\u0434\u0435\u0439 <em>(pratyaya)</em>, \u043A\u043E\u0442\u043E\u0440\u043E\u0435 [\u043F\u0440\u043E\u0438\u0441\u0445\u043E\u0434\u0438\u0442] <em>(ya\u1E25)</em> \u0432 \u0442\u043E\u043C [pa\u015Bu, \u043E\u0433\u0440\u0430\u043D\u0438\u0447\u0435\u043D\u043D\u043E\u043C \u0441\u0443\u0449\u0435\u0441\u0442\u0432\u0435,] <em>(tasya)</em> [\u043F\u043E\u0434\u0440\u0430\u0437\u0443\u043C\u0435\u0432\u0430\u0435\u0442] \u0443\u0442\u0440\u0430\u0442\u0443 <em>(ap\u0101ya\u1E25)</em> \u0441\u0438\u043B\u044B <em>(rasa)</em> \u0412\u044B\u0441\u0448\u0435\u0433\u043E <em>(para)</em> \u041D\u0435\u043A\u0442\u0430\u0440\u0430 \u0411\u0435\u0441\u0441\u043C\u0435\u0440\u0442\u0438\u044F <em>(am\u1E5Bta)</em>. \u0412 \u0441\u0432\u044F\u0437\u0438 \u0441 \u044D\u0442\u0438\u043C <em>(tena)</em>, [\u0442\u0430\u043A\u043E\u0435 \u043E\u0433\u0440\u0430\u043D\u0438\u0447\u0435\u043D\u043D\u043E\u0435 \u0441\u0443\u0449\u0435\u0441\u0442\u0432\u043E] \u0441\u0442\u0430\u043D\u043E\u0432\u0438\u0442\u0441\u044F \u0437\u0430\u0432\u0438\u0441\u0438\u043C\u044B\u043C <em>(asvatantrat\u0101m eti)</em>. \u0421\u0444\u0435\u0440\u043E\u0439 \u0432\u043B\u0438\u044F\u043D\u0438\u044F <em>(gocara\u1E25)</em> \u044D\u0442\u043E\u0433\u043E [\u0432\u043E\u0437\u043D\u0438\u043A\u043D\u043E\u0432\u0435\u043D\u0438\u044F \u0438\u0434\u0435\u0439 \u044F\u0432\u043B\u044F\u0435\u0442\u0441\u044F] <em>(sa\u1E25 ca)</em> Tanm\u0101tra --\u0442\u043E\u043D\u043A\u0438\u0439 \u0430\u0441\u043F\u0435\u043A\u0442 \u0432\u0441\u0435\u0433\u043E-- <em>(tanm\u0101tra)</em>.</p></div><div class="stanza"><a href="#s3.15" id="s3.15" class="num">3.15</a><p class="sans">\u0938\u094D\u0935\u0930\u0942\u092A\u093E\u0935\u0930\u0923\u0947 \u091A\u093E\u0938\u094D\u092F \u0936\u0915\u094D\u0924\u092F\u0903 \u0938\u0924\u0924\u094B\u0924\u094D\u0925\u093F\u0924\u093E\u0903 \u0964<br> \u092F\u0924\u0903 \u0936\u092C\u094D\u0926\u093E\u0928\u0941\u0935\u0947\u0927\u0947\u0928 \u0928 \u0935\u093F\u0928\u093E \u092A\u094D\u0930\u0924\u094D\u092F\u092F\u094B\u0926\u094D\u092D\u0935\u0903 \u0965\u0967\u096B\u0965</p><p class="trans">Svar\u016Bp\u0101vara\u1E47e c\u0101sya \u015Baktaya\u1E25 satatotthit\u0101\u1E25\u0964<br> Yata\u1E25 \u015Babd\u0101nuvedhena na vin\u0101 pratyayodbhava\u1E25 \u096515\u0965</p><p>\u0421\u0438\u043B\u044B <em>(\u015Baktaya\u1E25)</em><sup>1</sup> \u0432\u0441\u0435\u0433\u0434\u0430 <em>(satata)</em> \u0433\u043E\u0442\u043E\u0432\u044B <em>(utthit\u0101\u1E25)</em> \u0441\u043A\u0440\u044B\u0442\u044C <em>(\u0101vara\u1E47e)</em> \u0438\u0441\u0442\u0438\u043D\u043D\u0443\u044E \u043F\u0440\u0438\u0440\u043E\u0434\u0443 <em>(sva-r\u016Bpa)</em> \u044D\u0442\u043E\u0433\u043E [\u043E\u0433\u0440\u0430\u043D\u0438\u0447\u0435\u043D\u043D\u043E\u0433\u043E \u0441\u0443\u0449\u0435\u0441\u0442\u0432\u0430] <em>(ca asya)</em>, \u043F\u043E\u0442\u043E\u043C\u0443 \u0447\u0442\u043E <em>(yatas)</em> \u043D\u0435 \u0431\u044B\u0432\u0430\u0435\u0442 <em>(na)</em> \u0432\u043E\u0437\u043D\u0438\u043A\u043D\u043E\u0432\u0435\u043D\u0438\u044F <em>(udbhava\u1E25)</em> \u0438\u0434\u0435\u0439 <em>(pratyaya)</em> \u0431\u0435\u0437 <em>(vin\u0101)</em> \u0441\u043C\u0435\u0448\u0435\u043D\u0438\u044F <em>(anuvedhena)</em> \u0441\u043B\u043E\u0432 <em>(\u015Babda)</em>.</p><ol><li>Br\u0101hm\u012B, Yog\u012B\u015Bvar\u012B, M\u0101he\u015Bvar\u012B \u0438 \u0442.\u0434. <em>(\u0441\u0438\u043B\u044B, \u0432\u043E\u0437\u0433\u043B\u0430\u0432\u043B\u044F\u044E\u0449\u0438\u0435 \xAB\u0432\u0430\u0440\u0433\u0438\xBB, \u0433\u0440\u0443\u043F\u043F\u044B \u0431\u0443\u043A\u0432, \u043D\u0430\u043F\u0440\u0438\u043C\u0435\u0440, Br\u0101hm\u012B \u0432\u043E\u0437\u0433\u043B\u0430\u0432\u043B\u044F\u0435\u0442 Kavarga \u0438\u043B\u0438 \u0433\u0440\u0443\u043F\u043F\u0443 Ka, \u0441\u043E\u0441\u0442\u043E\u044F\u0449\u0443\u044E \u0438\u0437 ka, kha, ga, gha \u0438 \u1E45a )</em>.</li></ol></div><div class="stanza"><a href="#s3.16" id="s3.16" class="num">3.16</a><p class="sans">\u0938\u0947\u092F\u0902 \u0915\u094D\u0930\u093F\u092F\u093E\u0924\u094D\u092E\u093F\u0915\u093E \u0936\u0915\u094D\u0924\u093F\u0903 \u0936\u093F\u0935\u0938\u094D\u092F \u092A\u0936\u0941\u0935\u0930\u094D\u0924\u093F\u0928\u0940 \u0964<br> \u092C\u0928\u094D\u0927\u092F\u093F\u0924\u094D\u0930\u0940 \u0938\u094D\u0935\u092E\u093E\u0930\u094D\u0917\u0938\u094D\u0925\u093E \u091C\u094D\u091E\u093E\u0924\u093E \u0938\u093F\u0926\u094D\u0927\u094D\u092F\u0941\u092A\u092A\u093E\u0926\u093F\u0915\u093E \u0965\u0967\u096C\u0965</p><p class="trans">Seya\u1E41 kriy\u0101tmik\u0101 \u015Bakti\u1E25 \u015Bivasya pa\u015Buvartin\u012B\u0964<br> Bandhayitr\u012B svam\u0101rgasth\u0101 j\xF1\u0101t\u0101 siddhyupap\u0101dik\u0101 \u096516\u0965</p><p>\u042D\u0442\u0430 <em>(iyam)</em> \u0441\u0430\u043C\u0430\u044F <em>(s\u0101)</em> \u0421\u0438\u043B\u0430, \u0438\u043B\u0438 \u0428\u0430\u043A\u0442\u0438, <em>(\u015Bakti\u1E25)</em> \u0428\u0438\u0432\u044B <em>(\u015Bivasya)</em>, \u0447\u044C\u044F \u043F\u0440\u0438\u0440\u043E\u0434\u0430 <em>(\u0101tmik\u0101)</em> \u2014 \u0434\u0435\u044F\u0442\u0435\u043B\u044C\u043D\u043E\u0441\u0442\u044C <em>(kriy\u0101)</em>, \u043E\u0431\u0438\u0442\u0430\u0435\u0442 <em>(vartin\u012B)</em> \u0432 pa\u015Bu, \u043E\u0433\u0440\u0430\u043D\u0438\u0447\u0435\u043D\u043D\u043E\u043C \u0441\u0443\u0449\u0435\u0441\u0442\u0432\u0435, <em>(pa\u015Bu)</em> [\u0438] \u0441\u043A\u043E\u0432\u044B\u0432\u0430\u0435\u0442 [\u0435\u0433\u043E] <em>(bandhayitr\u012B)</em>. [\u0422\u0435\u043C \u043D\u0435 \u043C\u0435\u043D\u0435\u0435, \u043A\u043E\u0433\u0434\u0430 \u0428\u0430\u043A\u0442\u0438] \u043F\u043E\u0437\u043D\u0430\u0451\u0442\u0441\u044F <em>(j\xF1\u0101t\u0101)</em> \u043A\u0430\u043A \u043D\u0430\u0445\u043E\u0434\u044F\u0449\u0430\u044F\u0441\u044F [\u0432 pa\u015Bu] <em>(sth\u0101)</em> \u0432 \u0432\u0438\u0434\u0435 \u043F\u0443\u0442\u0438 <em>(m\u0101rga)</em> \u043A \u0441\u0432\u043E\u0435\u043C\u0443 \u0412\u044B\u0441\u0448\u0435\u043C\u0443 \u042F <em>(sva)</em>, [\u0442\u043E \u041E\u043D\u0430] \u043F\u0440\u0438\u0432\u043E\u0434\u0438\u0442 <em>(upap\u0101dik\u0101)</em> \u043A \u0443\u0441\u043F\u0435\u0445\u0443 <em>(siddhi)</em>.</p></div><div class="stanza"><a href="#s3.17-18" id="s3.17-18" class="num">3.17-18</a><p class="sans">\u0924\u0928\u094D\u092E\u093E\u0924\u094D\u0930\u094B\u0926\u092F\u0930\u0942\u092A\u0947\u0923 \u092E\u0928\u094B\u093D\u0939\u092E\u094D\u092C\u0941\u0926\u094D\u0927\u093F\u0935\u0930\u094D\u0924\u093F\u0928\u093E \u0964<br> \u092A\u0941\u0930\u094D\u092F\u0937\u094D\u091F\u0915\u0947\u0928 \u0938\u0902\u0930\u0941\u0926\u094D\u0927\u0938\u094D\u0924\u0926\u0941\u0924\u094D\u0925\u0902 \u092A\u094D\u0930\u0924\u094D\u092F\u092F\u094B\u0926\u094D\u092D\u0935\u092E\u094D \u0965\u0967\u096D\u0965</p><p class="sans">\u092D\u0941\u0919\u094D\u0915\u094D\u0924\u0947 \u092A\u0930\u0935\u0936\u094B \u092D\u094B\u0917\u0902 \u0924\u0926\u094D\u092D\u093E\u0935\u093E\u0924\u094D\u0938\u0902\u0938\u0930\u0947\u0926\u0924\u0903 \u0964<br> \u0938\u0902\u0938\u0943\u0924\u093F\u092A\u094D\u0930\u0932\u092F\u0938\u094D\u092F\u093E\u0938\u094D\u092F \u0915\u093E\u0930\u0923\u0902 \u0938\u092E\u094D\u092A\u094D\u0930\u091A\u0915\u094D\u0937\u094D\u092E\u0939\u0947 \u0965\u0967\u096E \u0965</p><p class="trans">Tanm\u0101trodayar\u016Bpe\u1E47a mano&#39;hambuddhivartin\u0101\u0964<br> Purya\u1E63\u1E6Dakena sa\u1E41ruddhastaduttha\u1E41 pratyayodbhavam \u096517\u0965</p><p class="trans">Bhu\u1E45kte parava\u015Bo bhoga\u1E41 tadbh\u0101v\u0101tsa\u1E41saredata\u1E25\u0964<br> Sa\u1E41s\u1E5Btipralayasy\u0101sya k\u0101ra\u1E47a\u1E41 sampracak\u1E63mahe \u096518\u0965</p><p>\u041F\u043E\u043B\u043D\u043E\u0441\u0442\u044C\u044E \u0437\u0430\u0431\u043B\u043E\u043A\u0438\u0440\u043E\u0432\u0430\u043D\u043D\u044B\u0439 \u0438 \u043E\u0441\u0430\u0436\u0434\u0451\u043D\u043D\u044B\u0439 <em>(sa\u1E41ruddha\u1E25)</em> \u041F\u0443\u0440\u044C\u044F\u0448\u0442\u0430\u043A\u043E\u0439 --Purya\u1E63\u1E6Daka-- <em>(purya\u1E63\u1E6Dakena)</em><sup>1</sup>, \u043A\u043E\u0442\u043E\u0440\u044B\u0439 \u043F\u0440\u043E\u0438\u0441\u0445\u043E\u0434\u0438\u0442 <em>(udaya-r\u016Bpe\u1E47a)</em> \u0438\u0437 [\u043F\u044F\u0442\u0438] Tanm\u0101tra --\u0442\u043E\u043D\u043A\u0438\u0445 \u044D\u043B\u0435\u043C\u0435\u043D\u0442\u043E\u0432-- <em>(tanm\u0101tra)</em> [\u0438] \u043E\u0431\u0438\u0442\u0430\u0435\u0442 <em>(vartin\u0101)</em> \u0432 \u0443\u043C\u0435 <em>(manas)</em>, \u044D\u0433\u043E <em>(aham)</em> [\u0438] \u0438\u043D\u0442\u0435\u043B\u043B\u0435\u043A\u0442\u0435*(buddhi)*, \u043F\u043E\u043A\u043E\u0440\u043D\u044B\u0439 [pa\u015Bu, \u043E\u0433\u0440\u0430\u043D\u0438\u0447\u0435\u043D\u043D\u043E\u0435 \u0441\u0443\u0449\u0435\u0441\u0442\u0432\u043E,] <em>(parava\u015Ba\u1E25)</em> \u0438\u0441\u043F\u044B\u0442\u044B\u0432\u0430\u0435\u0442 <em>(bhu\u1E45kte)</em> \u0432\u043E\u0437\u043D\u0438\u043A\u043D\u043E\u0432\u0435\u043D\u0438\u0435 <em>(udbhavam)</em> \u0438\u0434\u0435\u0439 <em>(pratyaya)</em>, \u043F\u0440\u043E\u0438\u0441\u0445\u043E\u0434\u044F\u0449\u0438\u0445 <em>(uttham)</em> \u0438\u0437 \u0442\u043E\u0433\u043E [Purya\u1E63\u1E6Daka] <em>(tad)</em> [\u0438 \u0441\u043E\u043F\u0440\u043E\u0432\u043E\u0436\u0434\u0430\u0435\u043C\u043E\u0435] \u043D\u0430\u0441\u043B\u0430\u0436\u0434\u0435\u043D\u0438\u0435\u043C [\u0443\u0434\u043E\u0432\u043E\u043B\u044C\u0441\u0442\u0432\u0438\u0435\u043C \u0438 \u0431\u043E\u043B\u044C\u044E, \u043F\u043E\u0440\u043E\u0436\u0434\u0451\u043D\u043D\u044B\u043C\u0438 \u044D\u0442\u0438\u043C\u0438 \u0441\u0430\u043C\u044B\u043C\u0438 \u0438\u0434\u0435\u044F\u043C\u0438] <em>(bhogam)</em>. [\u0422\u0430\u043A\u043E\u0435 \u0441\u0443\u0449\u0435\u0441\u0442\u0432\u043E] \u0442\u0440\u0430\u043D\u0441\u043C\u0438\u0433\u0440\u0438\u0440\u0443\u0435\u0442 <em>(sa\u1E41saret)</em> \u0438\u0437-\u0437\u0430 \u043F\u0440\u0438\u0441\u0443\u0442\u0441\u0442\u0432\u0438\u044F <em>(bh\u0101v\u0101t)</em> \u0442\u043E\u0433\u043E [Purya\u1E63\u1E6Daka] <em>(tad)</em>. \u0418\u0442\u0430\u043A <em>(atas)</em>, \u043C\u044B \u043E\u0431\u044A\u044F\u0441\u043D\u0438\u043C <em>(sampracak\u1E63mahe)</em> \u043F\u0440\u0438\u0447\u0438\u043D\u0443 <em>(k\u0101ra\u1E47am)</em> \u044D\u0442\u043E\u0433\u043E <em>(asya)</em> \u0440\u0430\u0441\u0442\u0432\u043E\u0440\u0435\u043D\u0438\u044F <em>(pralayasya)</em> \u0442\u0440\u0430\u043D\u0441\u043C\u0438\u0433\u0440\u0430\u0446\u0438\u0438 <em>(sa\u1E41s\u1E5Bti)</em>.</p><ol><li>\u0414\u043E\u0441\u043B. \xAB\u0433\u043E\u0440\u043E\u0434 \u0432\u043E\u0441\u044C\u043C\u0438\xBB, Purya\u1E63\u1E6Daka \u2014 \u044D\u043F\u0438\u0442\u0435\u0442 \u0442\u043E\u043D\u043A\u043E\u0433\u043E \u0442\u0435\u043B\u0430 <em>(s\u016Bk\u1E63ma\u015Bar\u012Bra, \u0442\u0430\u043A\u0436\u0435 li\u1E45ga\u015Bar\u012Bra)</em>, \u043F\u043E\u0441\u043A\u043E\u043B\u044C\u043A\u0443 \u043E\u043D\u043E \u0441\u043E\u0441\u0442\u043E\u0438\u0442 \u0438\u0437 buddhi <em>(\u0438\u043D\u0442\u0435\u043B\u043B\u0435\u043A\u0442\u0430)</em>, aha\u1E45k\u0101ra <em>(\u044D\u0433\u043E)</em>, manas <em>(\u0443\u043C\u0430)</em> \u0438 \u043F\u044F\u0442\u0438 Tanm\u0101tra, \u0442\u043E\u043D\u043A\u0438\u0445 \u044D\u043B\u0435\u043C\u0435\u043D\u0442\u043E\u0432. \u042D\u0442\u043E \u043F\u043E\u044F\u0441\u043D\u044F\u0435\u0442\u0441\u044F \u0441\u0430\u043C\u0438\u043C\u0438 \u0430\u0432\u0442\u043E\u0440\u043E\u043C \u0434\u0430\u043B\u0435\u0435.</li></ol></div><div class="stanza"><a href="#s3.19" id="s3.19" class="num">3.19</a><p class="sans">\u092F\u0926\u093E \u0924\u094D\u0935\u0947\u0915\u0924\u094D\u0930 \u0938\u0902\u0930\u0942\u0922\u0938\u094D\u0924\u0926\u093E \u0924\u0938\u094D\u092F \u0932\u092F\u094B\u0926\u092F\u094C \u0964<br> \u0928\u093F\u092F\u091A\u094D\u091B\u0928\u094D\u092D\u094B\u0915\u094D\u0924\u0943\u0924\u093E\u092E\u0947\u0924\u093F \u0924\u0924\u0936\u094D\u091A\u0915\u094D\u0930\u0947\u0936\u094D\u0935\u0930\u094B \u092D\u0935\u0947\u0924\u094D \u0965\u0967\u096F\u0965</p><p class="trans">Yad\u0101 tvekatra sa\u1E41r\u016B\u1E0Dhastad\u0101 tasya layodayau\u0964<br> Niyacchanbhokt\u1E5Bt\u0101meti tata\u015Bcakre\u015Bvaro bhavet \u096519\u0965</p><p>\u041D\u043E <em>(tu)</em>, \u043A\u043E\u0433\u0434\u0430 <em>(yad\u0101)</em> [\u043E\u0433\u0440\u0430\u043D\u0438\u0447\u0435\u043D\u043D\u043E\u0435 \u0441\u0443\u0449\u0435\u0441\u0442\u0432\u043E] \u043F\u0440\u043E\u0447\u043D\u043E \u0443\u043A\u043E\u0440\u0435\u043D\u044F\u0435\u0442\u0441\u044F <em>(sa\u1E41r\u016B\u1E0Dha\u1E25)</em> \u0432 \u043E\u0434\u043D\u043E\u0439 \u0442\u043E\u0447\u043A\u0435 --\u0432 \u043F\u0440\u0438\u043D\u0446\u0438\u043F\u0435 \u0421\u043F\u0430\u043D\u0434\u044B-- <em>(ekatra)</em>, \u0442\u043E\u0433\u0434\u0430 <em>(tad\u0101)</em>, \u043A\u043E\u043D\u0442\u0440\u043E\u043B\u0438\u0440\u0443\u044F <em>(niyacchan)</em> \u0438\u0441\u0447\u0435\u0437\u043D\u043E\u0432\u0435\u043D\u0438\u0435 \u0438 \u043F\u043E\u044F\u0432\u043B\u0435\u043D\u0438\u0435 <em>(laya-udayau)</em> \u0442\u043E\u0433\u043E [Purya\u1E63\u1E6Daka] <em>(tasya)</em>, [\u044D\u0442\u043E \u0441\u0443\u0449\u0435\u0441\u0442\u0432\u043E] \u0441\u0442\u0430\u043D\u043E\u0432\u0438\u0442\u0441\u044F [\u043D\u0430\u0441\u0442\u043E\u044F\u0449\u0438\u043C] \u043D\u0430\u0441\u043B\u0430\u0436\u0434\u0430\u044E\u0449\u0438\u043C\u0441\u044F <em>(bhokt\u1E5Bt\u0101m eti)</em> [\u0438,] \u043A\u0430\u043A \u0441\u043B\u0435\u0434\u0441\u0442\u0432\u0438\u0435 <em>(tatas)</em>, [\u0442\u0430\u043A\u0436\u0435] \u043F\u0440\u0435\u0432\u0440\u0430\u0449\u0430\u0435\u0442\u0441\u044F <em>(bhavet)</em> \u0432\u043E \u0412\u043B\u0430\u0441\u0442\u0438\u0442\u0435\u043B\u044F <em>(\u012B\u015Bvara\u1E25)</em> \u0433\u0440\u0443\u043F\u043F\u044B [\u015Bakti, \u0442\u043E \u0435\u0441\u0442\u044C \u0441\u0438\u043B] <em>(cakra)</em>.</p></div><h2 id="\u0447\u0430\u0441\u0442\u044C-iv-\u044D\u043F\u0438n\u043E\u0433" tabindex="-1">\u0427\u0430\u0441\u0442\u044C IV: \u042D\u043F\u0438\u043B\u043E\u0433 <a class="header-anchor" href="#\u0447\u0430\u0441\u0442\u044C-iv-\u044D\u043F\u0438n\u043E\u0433" aria-hidden="true">#</a></h2><p><strong>\u0414\u0432\u0435 \u0437\u0430\u043A\u043B\u044E\u0447\u0438\u0442\u0435\u043B\u044C\u043D\u044B\u0435 \u0441\u0442\u0440\u043E\u0444\u044B</strong></p><div class="stanza"><a href="#s4.1" id="s4.1" class="num">4.1</a><p class="sans">\u0905\u0917\u093E\u0927\u0938\u0902\u0936\u092F\u093E\u092E\u094D\u092D\u094B\u0927\u093F\u0938\u092E\u0941\u0924\u094D\u0924\u0930\u0923\u0924\u093E\u0930\u093F\u0923\u0940\u092E\u094D \u0964<br> \u0935\u0928\u094D\u0926\u0947 \u0935\u093F\u091A\u093F\u0924\u094D\u0930\u093E\u0930\u094D\u0925\u092A\u0926\u093E\u0902 \u091A\u093F\u0924\u094D\u0930\u093E\u0902 \u0924\u093E\u0902 \u0917\u0941\u0930\u0941\u092D\u093E\u0930\u0924\u0940\u092E\u094D \u0965\u0967\u0965</p><p class="trans">Ag\u0101dhasa\u1E41\u015Bay\u0101mbhodhisamuttara\u1E47at\u0101ri\u1E47\u012Bm\u0964<br> Vande vicitr\u0101rthapad\u0101\u1E41 citr\u0101\u1E41 t\u0101\u1E41 gurubh\u0101rat\u012Bm \u09651\u0965</p><p>\u042F \u043F\u0440\u0435\u043A\u043B\u043E\u043D\u044F\u044E\u0441\u044C <em>(vande)</em> \u043F\u0435\u0440\u0435\u0434 \u044D\u0442\u043E\u0439 <em>(t\u0101m)</em> \u0432\u043E\u0441\u0445\u0438\u0442\u0438\u0442\u0435\u043B\u044C\u043D\u043E\u0439 <em>(citr\u0101m)</em> \u0440\u0435\u0447\u044C\u044E <em>(bh\u0101rat\u012Bm)</em> \u0413\u0443\u0440\u0443 <em>(guru)</em>, [\u0438\u0441\u043F\u043E\u043B\u043D\u0435\u043D\u043D\u043E\u0439] \u043C\u043D\u043E\u0436\u0435\u0441\u0442\u0432\u0430 <em>(vicitra)</em> \u0441\u043B\u043E\u0432 --pada-- <em>(pad\u0101m)</em> [\u0438 \u0441\u043E\u043E\u0442\u0432\u0435\u0442\u0441\u0442\u0432\u0443\u044E\u0449\u0435\u0433\u043E \u0438\u043C] \u0441\u043C\u044B\u0441\u043B\u0430 <em>(artha)</em>, [\u043A\u043E\u0442\u043E\u0440\u0430\u044F] \u043F\u043E\u0437\u0432\u043E\u043B\u044F\u0435\u0442 <em>(t\u0101ri\u1E47\u012Bm)</em> \u0431\u0435\u0437\u043E\u043F\u0430\u0441\u043D\u043E \u043F\u0435\u0440\u0435\u0441\u0435\u0447\u044C <em>(samuttara\u1E47a)</em> \u0431\u0435\u0437\u0434\u043E\u043D\u043D\u044B\u0439 <em>(ag\u0101dha)</em> \u043E\u043A\u0435\u0430\u043D <em>(ambhodhi)</em> \u0441\u043E\u043C\u043D\u0435\u043D\u0438\u044F <em>(sa\u1E41\u015Baya)</em>.</p></div><div class="stanza"><a href="#s4.2" id="s4.2" class="num">4.2</a><p class="sans">\u0932\u092C\u094D\u0927\u094D\u0935\u093E\u092A\u094D\u092F\u0932\u092D\u094D\u092F\u092E\u0947\u0924\u091C\u094D\u091C\u094D\u091E\u093E\u0928\u0927\u0928\u0902 \u0939\u0943\u0926\u094D\u0917\u0941\u0939\u093E\u0928\u094D\u0924\u0915\u0943\u0924\u0928\u093F\u0939\u093F\u0924\u0947\u0903 \u0964<br> \u0935\u0938\u0941\u0917\u0941\u092A\u094D\u0924\u0935\u091A\u094D\u091B\u093F\u0935\u093E\u092F \u0939\u093F \u092D\u0935\u0924\u093F \u0938\u0926\u093E \u0938\u0930\u094D\u0935\u0932\u094B\u0915\u0938\u094D\u092F \u0965\u0968\u0965</p><p class="trans">Labdhv\u0101pyalabhyametajj\xF1\u0101nadhana\u1E41 h\u1E5Bdguh\u0101ntak\u1E5Btanihite\u1E25\u0964<br> Vasuguptavacchiv\u0101ya hi bhavati sad\u0101 sarvalokasya \u09652\u0965</p><p>\u041A\u0440\u043E\u043C\u0435 \u0442\u043E\u0433\u043E <em>(api)</em>, \u043E\u0431\u0440\u0435\u0442\u0435\u043D\u0438\u0435 <em>(labdhv\u0101)</em> \u044D\u0442\u043E\u0433\u043E <em>(etad)</em> \u0441\u043E\u043A\u0440\u043E\u0432\u0438\u0449\u0430 <em>(dhanam)</em> \u0437\u043D\u0430\u043D\u0438\u0439 <em>(j\xF1\u0101na)</em>, \u043A\u043E\u0442\u043E\u0440\u043E\u0435 \u0441\u043B\u043E\u0436\u043D\u043E \u043E\u0431\u0440\u0435\u0441\u0442\u0438 <em>(alabhyam)</em>, [\u0438 \u0435\u0433\u043E] \u0434\u043E\u0431\u0440\u043E\u0441\u043E\u0432\u0435\u0441\u0442\u043D\u043E\u0435 <em>(k\u1E5Bta)</em> \u0441\u043E\u0445\u0440\u0430\u043D\u0435\u043D\u0438\u0435 <em>(nihite\u1E25)</em> \u0432 <em>(anta)</em> \u043F\u0435\u0449\u0435\u0440\u0435 <em>(guha)</em> \u0441\u0435\u0440\u0434\u0446\u0430 <em>(h\u1E5Bd)</em>, \u043D\u0435\u0441\u043E\u043C\u043D\u0435\u043D\u043D\u043E <em>(hi)</em>, \u0432\u0441\u0435\u0433\u0434\u0430 <em>(sad\u0101)</em> \u0441\u043B\u0443\u0436\u0438\u0442 <em>(bhavati)</em> \u0432\u043E \u0431\u043B\u0430\u0433\u043E <em>(\u015Biv\u0101ya)</em> \u0432\u0441\u0435\u0433\u043E <em>(sarva)</em> \u043C\u0438\u0440\u0430 <em>(lokasya)</em>, \u043F\u043E\u0434\u043E\u0431\u043D\u043E \u0442\u043E\u043C\u0443 \u043A\u0430\u043A <em>(vat)</em> [\u043E\u043D\u043E \u043F\u043E\u0441\u043B\u0443\u0436\u0438\u043B\u043E \u0432\u043E \u0431\u043B\u0430\u0433\u043E] \u0412\u0430\u0441\u0443\u0433\u0443\u043F\u0442\u044B <em>(vasugupta)</em>.</p></div>',58),i=[r];function p(n,d,h,v,y,l){return m(),e("div",null,i)}var b=a(t,[["render",p]]);export{u as __pageData,b as default};
